function buildTarifaLine(finca, quote) {
  function _isFlatCat(c) { return c === 'temporada_alta' || c === 'semana_santa'; }
  function _renderLine(li, capMin, personas, prefix) {
    var head = formatCurrency(li.base_per_night) + ' / noche';
    var isFlat = _isFlatCat(li.category);
    var personasStr = personas > 0 ? ' para ' + personas + ' persona' + (personas === 1 ? '' : 's') : '';
    if (isFlat) {
      // flat (temporada alta / semana santa): no per-person at quote time, always show personas count
      return prefix + head + personasStr;
    }
    // additive (standard / festivo)
    if (personas > capMin && li.extra_per_person > 0 && capMin > 0) {
      // group exceeds cap_min → show extra-person formula
      head += ' + ' + formatCurrency(li.extra_per_person) + ' por persona a partir de ' + capMin;
      return prefix + head;
    }
    // fits within cap_min → show plain rate + personas (so customer knows boundary)
    return prefix + head + personasStr;
  }
  if (quote && Array.isArray(quote.line_items) && quote.line_items.length && quote.total_nights > 0) {
    var capMin = Number(finca.capacidad_minima) || 0;
    var personasN = Number(quote.personas) || 0;
    if (quote.line_items.length === 1) {
      return _renderLine(quote.line_items[0], capMin, personasN, '💰 ');
    }
    // mixed temporadas → breakdown
    var lines = ['💰 *Cotización para esas fechas:*'];
    quote.line_items.forEach(function (li) {
      var nightsLabel = li.nights + ' noche' + (li.nights === 1 ? '' : 's');
      lines.push('   • ' + nightsLabel + ' ' + li.label + ': ' + _renderLine(li, capMin, personasN, ''));
    });
    return lines.join('\n');
  }
  // Fallback (no fechas): muestra base estándar + extras desde cap_min si aplica
  var capMin = Number(finca.capacidad_minima) || 0;
  var base = Number(finca.precio_base_noche || finca.precio_noche_base || 0);
  var xtra = Number(finca.precio_persona_extra_base || finca.precio_persona_extra || 0);
  if (base > 0) {
    var head = '💰 desde ' + formatCurrency(base) + ' / noche';
    if (xtra > 0 && capMin > 0) {
      head += ' + ' + formatCurrency(xtra) + ' por persona a partir de ' + capMin;
    }
    return head;
  }
  if (finca.precio_festivo || finca.precio_fin_semana || finca.precio_referencia_noche) {
    return '💰 desde ' + formatCurrency(finca.precio_festivo || finca.precio_fin_semana || finca.precio_referencia_noche) + ' / noche';
  }
  return null;
}

function buildFincaCard(finca) {
  if (!finca || typeof finca !== 'object') return null;
  const title = String(finca.codigo_original || finca.finca_id || 'Finca').trim();
  const code = String(finca.codigo_original || finca.finca_id || '').trim();
  const highlights = buildHighlightLines(finca);
  const sc = _safeSearchCriteria();
  const quote = computeQuote(finca, sc.fecha_inicio, sc.fecha_fin, sc.personas);
  const tarifa = buildTarifaLine(finca, quote);
  const tipos = (Array.isArray(finca.tipo_evento) ? finca.tipo_evento : []).map(function(t){ return String(t).toLowerCase(); });
  const aceptaEventos = tipos.some(function(t){ return t.indexOf('evento')>=0 || t.indexOf('fiesta')>=0; });
  const aceptaFamiliar = tipos.some(function(t){ return t.indexOf('familiar')>=0 || t.indexOf('vacacion')>=0; });
  const indicadoresExtra = [];
  if (finca.pet_friendly === true) indicadoresExtra.push('🐕 Acepta mascotas');
  if (aceptaEventos) indicadoresExtra.push('🎉 Apto para eventos / fiestas');
  else if (aceptaFamiliar) indicadoresExtra.push('👨‍👩‍👧 Vacacional / familiar');
  const parts = [
    '☀️🌴*' + title + '*🌴☀️',
    code && code !== title ? code : null,
    null,
    ...highlights.map((line) => '- ' + line),
    finca.tiempo_en_vehiculo ? '🚗 ' + String(finca.tiempo_en_vehiculo) + ' al pueblo' : null,
    finca.acomodacion_por_habitacion
      ? 'Acomodación por habitación: ' + String(finca.acomodacion_por_habitacion)
      : finca.especificacion_habitaciones
        ? 'Acomodación: ' + String(finca.especificacion_habitaciones)
        : null,
    finca.servicios_adicionales_texto
      ? 'Servicios adicionales: ' + String(finca.servicios_adicionales_texto)
      : null,
    (function() {
      var emp = finca.empleada_obligatorio;
      var sc2 = _safeSearchCriteria();
      var pp = Number(sc2.personas) || 0;
      var c = resolveEmpleadaCount(emp, pp);
      if (c <= 0) return null;
      var per8 = Number(finca.servicio_empleada_valor_8h || 0);
      if (per8 <= 0) return null;
      var perDay = per8 * c;
      var nightsCount = (quote && quote.total_nights) ? quote.total_nights : 0;
      var head = '👩\u200d🍳 Servicio empleada obligatorio: ' + formatCurrency(perDay) + '/día';
      if (c > 1) head += ' (' + c + ' empleadas)';
      if (nightsCount > 0) head += ' · total ' + formatCurrency(perDay * nightsCount) + ' por ' + nightsCount + ' noche' + (nightsCount===1?'':'s');
      return head;
    })(),
    indicadoresExtra.length ? indicadoresExtra.join('  •  ') : null,
    null,
    tarifa,
  ].filter((value) => value !== null && value !== undefined && String(value).trim() !== '');
  return parts.join('\n');
}

