  var criteria = $('Get Context-conversations1').item.json.search_criteria || $('Get Context-conversations1').item.json.context?.search_criteria || {};
  var confirmData = toolOutputParsed.confirmation_data_update || {};
  var extras = $('Get Context-conversations1').item.json.extras || {};
  var prevConfirm = extras.confirming_reservation || {};
  var merged = Object.assign({}, prevConfirm, confirmData);

  var noches = daysBetweenIsoDates(criteria.fecha_inicio, criteria.fecha_fin);
  var quote = computeQuote(finca, criteria.fecha_inicio, criteria.fecha_fin, criteria.personas);
  var tarifaNoche, limpieza, subtotal, total, deposito;
  var empleadaPerDay = 0, empleadaTotal = 0, empleadaCount = 0;
  if (quote && quote.line_items.length) {
    tarifaNoche   = quote.total_nights ? Math.round(quote.subtotal_noches / quote.total_nights) : 0;
    subtotal      = quote.subtotal_noches;
    limpieza      = quote.limpieza_final;
    deposito      = quote.deposito_seguridad;
    empleadaPerDay= Number(quote.servicio_empleada_per_day || 0);
    empleadaTotal = Number(quote.servicio_empleada_total || 0);
    empleadaCount = Number(quote.servicio_empleada_count || 0);
    total         = quote.total;
  } else {
    tarifaNoche = Number(finca.precio_base_noche || finca.precio_noche_base || finca.precio_fin_semana || finca.precio_referencia_noche || 0);
    limpieza    = Number(finca.limpieza_final_valor || 0);
    deposito    = Number(finca.deposito_seguridad || 0);
    // Empleada fallback: compute manually from finca data if quote unavailable.
    var empObj  = finca.empleada_obligatorio || {};
