    empleadaPerDay = empleadaCount > 0 ? Number(finca.servicio_empleada_valor_8h || 0) * empleadaCount : 0;
    empleadaTotal  = empleadaPerDay * (noches || 0);
    subtotal    = noches && tarifaNoche ? noches * tarifaNoche : 0;
    total       = subtotal + limpieza + deposito + empleadaTotal;
  }

  var payload = {
    property_code: finca.codigo_original || finca.finca_id || '',
    property_name: finca.nombre || '',
    property_zone: finca.zona || '',
    property_municipio: finca.municipio || '',
    fecha_inicio: criteria.fecha_inicio || '',
    fecha_fin: criteria.fecha_fin || '',
    noches: noches,
    check_in: '15:00h',
    check_out: '11:00h',
    tarifa_noche: tarifaNoche,
    limpieza_final: limpieza,
    deposito: deposito,
    servicio_empleada_per_day: empleadaPerDay,
    servicio_empleada_total: empleadaTotal,
    servicio_empleada_count: empleadaCount,
    quote_breakdown: quote && quote.line_items ? quote.line_items : [],
    huespedes: criteria.personas || '',
    subtotal: subtotal,
    total: total,
    anticipo_requerido: Math.round(total * 0.5),
    client_name: merged.nombre_completo || '',
    client_document_type: merged.tipo_documento || '',
    client_document_number: merged.numero_documento || '',
    client_phone: merged.celular || $('Merge Sets1').item.json.conversation_key || '',
    client_email: merged.correo || '',
    client_address: merged.direccion || '',
    tiempo_en_vehiculo: finca.tiempo_en_vehiculo || '',
    acomodacion_por_habitacion: finca.acomodacion_por_habitacion || '',
    servicios_adicionales_texto: finca.servicios_adicionales_texto || '',
    payment_methods_text: $('config').item.json.payment_methods_text || '',
    company_knowledge: $('config').item.json.company_knowledge || '',
