// ─── DETERMINISTIC TEMPLATE RENDERING ───
// LLMs paraphrase even with strict-literal prompts. For the three
// confirming_reservation intents that have an operator-edited template
// in agent_settings, we override the LLM's final_whatsapp_text and use
// the template verbatim. Operators control these texts from /settings;
// the LLM's job here is just to detect the intent and identify the
// finca, not to rewrite the message.
function _renderTemplate(template, fullName) {
  var s = String(template == null ? '' : template);
  if (!s.trim()) return '';
  var first = String(fullName || '').trim().split(/\s+/)[0];
  if (first) {
    // Replace "(NOMBRE)" → "<first>,"
    s = s.replace(/\(NOMBRE\)/g, first + ',');
  } else {
    // Remove "(NOMBRE) " (with trailing space) when name unknown
    s = s.replace(/\(NOMBRE\)\s*/g, '');
  }
  return s;
}
function _confirmingTemplateOverride(toolChosen, intent, isFirstConfirmingTurn, fullName) {
  var cfg = {};
  try { cfg = $('config').item.json || {}; } catch (e) {}
  // VISIT_REQUEST: cross-cutting, from ANY agent. Cliente pidió
  // visitar la propiedad sin haber dado una fecha. NO transferir
  // a humano todavía — el sistema le ofrece agendar visita o
  // videollamada usando el template visit_offer_message_template.
  if (intent === 'VISIT_REQUEST') {
    return _renderTemplate(cfg.visit_offer_message_template, fullName);
  }
  if (toolChosen !== 'confirming_reservation_agent') return null;
  if (intent === 'REQUEST_CONFIRMATION_DATA' && isFirstConfirmingTurn) {
    return _renderTemplate(cfg.confirming_intro_message_template, fullName);
  }
  if (intent === 'DOCUMENT_READY') {
    return _renderTemplate(cfg.confirming_document_ready_message_template, fullName);
  }
  if (intent === 'RESERVATION_APPROVED') {
    return _renderTemplate(cfg.reservation_approved_message_template, fullName);
  }
  return null;
}

// === [Rehydrate] Merge LLM-emitted finca with the FULL data from BIT ===
// El LLM puede emitir fincas_mostradas con campos incompletos. Para
// que las cards y selecciones tengan TODOS los campos (precio extra
// por persona, capacidad, amenidades, quote pre-calculado, etc.),
// buscamos cada finca_id en la respuesta de Build Inventory Tool
// Response (BIT) y mergeamos. BIT toma precedencia sobre el LLM.
function _bitFincaIndex() {
  // BIT corre en sub-exec (toolWorkflow inventory_reader_tool), así que
  // su output no es alcanzable vía `$('Build Inventory Tool Response')`
  // desde la parent exec donde corre CodeJS1. Para rehidratar las fincas
  // emitidas por el LLM (que vienen con campos mínimos, sin quote), BIT
  // persiste su respuesta en conversations.last_inventory_items en cada
  // llamada al tool. Aquí leemos esa caché vía el context persistido
  // que Get Context-conversations1 ya trae con SELECT u.*.
  var idx = {};
  try {
    var ctx = $('Get Context-conversations1').item.json || {};
    var cached = ctx.last_inventory_items;
    if (typeof cached === 'string') {
      try { cached = JSON.parse(cached); } catch (e) { cached = null; }
    }
    if (!cached || typeof cached !== 'object') return idx;
    var lists = [];
    if (Array.isArray(cached.items)) lists.push(cached.items);
    if (Array.isArray(cached.similar_items)) lists.push(cached.similar_items);
    if (cached.selected_finca && typeof cached.selected_finca === 'object') lists.push([cached.selected_finca]);
    for (var li = 0; li < lists.length; li++) {
      for (var ii = 0; ii < lists[li].length; ii++) {
        var it = lists[li][ii];
        if (it && it.finca_id) idx[String(it.finca_id)] = it;
      }
    }
  } catch (e) {}
  return idx;
}
function _rehydrateFinca(llmFinca, bitIndex) {
  if (!llmFinca || typeof llmFinca !== 'object') return llmFinca;
  var id = String(llmFinca.finca_id || llmFinca.codigo_original || '').trim();
  if (!id) return llmFinca;
  var bit = bitIndex[id];
  if (!bit) return llmFinca;
  // BIT data takes precedence: it has the full sanitized item + pre-calculated quote.
  return Object.assign({}, llmFinca, bit);
}

function buildPropertySequence(tool, toolOutputParsed, finalWhatsappText) {
  const intent = toolOutputParsed?.intent || null;
  const _bitIndex = _bitFincaIndex();
  const selectedFinca = (function() {
    var sf = (toolOutputParsed && toolOutputParsed.selected_finca && typeof toolOutputParsed.selected_finca === 'object') ? toolOutputParsed.selected_finca : null;
    return sf ? _rehydrateFinca(sf, _bitIndex) : null;
  })();
  const fincasMostradas = (Array.isArray(toolOutputParsed?.fincas_mostradas)
    ? toolOutputParsed.fincas_mostradas.filter((item) => item && typeof item === 'object')
    : []
  ).map(function(it) { return _rehydrateFinca(it, _bitIndex); });

  const sequence = [];

  if (tool === 'offering_agent' && intent === 'SHOW_OPTIONS' && fincasMostradas.length) {
    for (const finca of fincasMostradas) {
      const card = buildFincaCard(finca);
      const cardMessage = createTextMessage(card, {
        property_title: finca?.codigo_original || finca?.finca_id || null,
        property_id: finca?.finca_id || null,
      });
      if (cardMessage) sequence.push(cardMessage);
      sequence.push(...buildMediaMessages(finca));
    }

    // Closing message: only when we showed >= 2 fincas in this batch.
    // The agent (n8n) sends one card+media per finca; this final text invites
    // the client to react ("¿qué te parecen?") and tees up the next round
    // (presupuesto / amenidades / nuevas zonas). The follow-on cron picks up
    // from here if the client doesn't reply within 3h.
    if (fincasMostradas.length >= 2) {
      const closingTextRaw = (function() {
        try {
          const raw = $('config').item.json.offering_closing_message;
          const trimmed = String(raw || '').trim();
          if (trimmed) return trimmed;
        } catch (e) {}
        return 'Qué te parecen? 🤩\n\nTengo más opciones si querés cambiar zona, presupuesto o alguna amenidad';
      })();
      const closingMsg = createTextMessage(closingTextRaw);
      if (closingMsg) sequence.push(closingMsg);
    }

    return sequence;
  }

  if (tool === 'confirming_reservation_agent') {
    // Build text first
    const trailingText = createTextMessage(finalWhatsappText);

    // Sub-flow #1: DOCUMENT_READY — text + reservation PDF
    if (intent === 'DOCUMENT_READY') {
      const documentItem = createReservationDocumentItem(selectedFinca, toolOutputParsed, finalWhatsappText);
      if (documentItem) {
        sequence.push(documentItem);
        return sequence;
      }
      // fallback if PDF generation failed
      if (trailingText) sequence.push(trailingText);
      return sequence;
    }

    // Sub-flow #2: REQUEST_CONFIRMATION_DATA on first state-transition into CONFIRMING_RESERVATION
    // → text (the Pasos para Reservar template) + video (from settings)
    const isFirstConfirmingTurn =
      intent === 'REQUEST_CONFIRMATION_DATA' &&
      (function() {
        try {
          const prevState = $('Get Context-conversations1').item.json.current_state || null;
          return prevState !== 'CONFIRMING_RESERVATION';
        } catch (e) { return false; }
      })();

    if (trailingText) sequence.push(trailingText);

    if (isFirstConfirmingTurn) {
      let videoUrl = '';
      try { videoUrl = String($('config').item.json.confirming_video_url || '').trim(); } catch (e) {}
      if (videoUrl && /^https?:\/\//i.test(videoUrl)) {
        sequence.push({
          type: 'media_group',
          content: '',
          media_url: videoUrl,
          media_urls: [videoUrl],
          property_title: null,
          property_id: null,
          media_count: 1,
        });
      }
    }

    return sequence;
  }

  const documentsToSend = normalizeDocumentsToSend(toolOutputParsed?.documents_to_send);

  if (documentsToSend.length) {
    sequence.push(...createCompanyDocumentItems(documentsToSend, finalWhatsappText));
    return sequence;
  }

  if (selectedFinca && ['offering_agent', 'verifying_availability_agent', 'qa_agent'].includes(tool)) {
    const trailingText = createTextMessage(finalWhatsappText);
    if (trailingText) sequence.push(trailingText);
    return sequence;
  }

  return [];
}


function buildSelectionNotificationCandidate({ toolChosen, toolOutputParsed, normalizedPostActions, currentState, currentStateAfter }) {
