    shouldNotify:
      (toolChosen === 'offering_agent' &&
        intent === 'CLIENT_CHOSE' &&
        (currentStateAfter === 'CONFIRMING_RESERVATION' || currentStateAfter === 'VERIFYING_AVAILABILITY') &&
        Boolean(selectedFincaId)) ||
