const toNumber = (value, fallback = null) => {
  if (value === undefined || value === null || value === '') return fallback;
  // strip $, commas, spaces — keeps digits, dot, minus
  const num = Number(String(value).replace(/[^\d.-]/g, ''));
  return Number.isFinite(num) ? num : fallback;
};

const toBool = (value, fallback = false) => {
  if (typeof value === 'boolean') return value;
  if (value === undefined || value === null || value === '') return fallback;
  const normalized = String(value).trim().toLowerCase();
  if (['true', '1', 'si', 'sí', 'yes', 'y', 'activo', 'activa'].includes(normalized)) return true;
  if (['false', '0', 'no', 'n', 'inactivo', 'inactiva'].includes(normalized)) return false;
  return fallback;
};

const toCsv = (value) => {
  if (Array.isArray(value)) return value.filter(Boolean).map((item) => String(item).trim()).filter(Boolean);
  if (!value) return [];
  return String(value)
    .split(/[,;|]/)
    .map((item) => item.trim())
    .filter(Boolean);
};

function parseEmpleadaObligatoria(raw) {
  // Returns {count: number, per_personas: number|null, raw: string|null}.
  //   ""/null/0/"no"        -> {count:0, per_personas:null}    (not mandatory)
  //   "2" / 2               -> {count:2, per_personas:null}    (2 empleadas always)
  //   "1 por cada 8 personas" -> {count:0, per_personas:8}     (1 employee per 8 people)
  //   "1 cada 6"            -> {count:0, per_personas:6}
  if (raw === null || raw === undefined) return {count: 0, per_personas: null, raw: null};
  if (typeof raw === 'boolean') return {count: raw ? 1 : 0, per_personas: null, raw: String(raw)};
  if (typeof raw === 'number' && isFinite(raw)) return {count: Math.max(0, Math.floor(raw)), per_personas: null, raw: String(raw)};
  const s = String(raw).trim();
  if (!s) return {count: 0, per_personas: null, raw: null};
  const norm = s.toLowerCase()
    .replace(/[áä]/g,'a').replace(/[éë]/g,'e').replace(/[íï]/g,'i')
    .replace(/[óö]/g,'o').replace(/[úü]/g,'u');
  // Negative shortcuts
  if (/^(no|n|0|ninguna|ningun|sin|opcional|opcionales|no obligatori\w*)$/i.test(norm)) {
    return {count: 0, per_personas: null, raw: s};
  }
  // "X por cada Y (personas)?"
  let m = norm.match(/(\d+)\s*(?:empleadas?|emp\.?)?\s*(?:por\s+cada|cada|por|\/)\s*(\d+)\s*(?:personas?|huespedes?|pax)?/i);
  if (m) {
    const c = Number(m[1]);
    const ratio = Number(m[2]);
    if (isFinite(c) && c > 0 && isFinite(ratio) && ratio > 0) {
      return {count: 0, per_personas: Math.round(ratio / c), raw: s};
    }
  }
  // Plain number "2" or "2 empleadas"
  m = norm.match(/^\s*(\d+)\s*(?:empleadas?|emp\.?)?\s*$/);
  if (m) {
    const n = Number(m[1]);
    return {count: Math.max(0, Math.floor(n)), per_personas: null, raw: s};
  }
  // True-ish words → 1 (legacy boolean)
  if (/^(si|sí|s|true|y|yes|obligatori\w*)$/i.test(norm)) {
    return {count: 1, per_personas: null, raw: s};
  }
  // Fallback: extract any leading int
  m = norm.match(/(\d+)/);
  if (m) return {count: Math.max(0, parseInt(m[1],10)), per_personas: null, raw: s};
  return {count: 0, per_personas: null, raw: s};
}
function resolveEmpleadaCount(empObj, personas) {
  if (!empObj || typeof empObj !== 'object') return 0;
  if (empObj.count > 0) return empObj.count;
  if (empObj.per_personas && personas > 0) {
    return Math.max(1, Math.round(personas / empObj.per_personas));
  }
