function _seasonsBIRP() {
  try {
    var raw = $('Get agent settings').item.json.pricing_seasons;
    if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch (e) { raw = null; } }
    if (!raw || typeof raw !== 'object') return { festivos_y_puentes: [], semana_santa: [], temporada_alta: [] };
