function _bookingOverlapsUnavailable(item, fechaInicio, fechaFin) {
  if (!fechaInicio || !fechaFin) return false;
  const ranges = Array.isArray(item.fechas_no_disponibles) ? item.fechas_no_disponibles : [];
  if (!ranges.length) return false;
  const start = String(fechaInicio).slice(0,10);
  const end = String(fechaFin).slice(0,10);
  // booking is [start, end). a "blocked" range is [from, to] inclusive.
  // overlap iff start <= range.to AND end > range.from
  for (const r of ranges) {
    const rf = String(r.from || '').slice(0,10);
    const rt = String(r.to || '').slice(0,10);
    if (!rf || !rt) continue;
    if (start <= rt && end > rf) return true;
  }
  return false;
}

function _effectiveMinNochesBIRP(item, fechaInicio, fechaFin) {
  var ngs = _enumerateNightsBIRP(fechaInicio, fechaFin);
  if (!ngs.length) return Number(item && item.min_noches) || 1;
  var seasons = _seasonsBIRP();
  var maxReq = 0; var hasStandard = false;
  ngs.forEach(function(iso){
    var cls = _classifyNightBIRP(iso, seasons);
    if (cls.category === 'standard') { hasStandard = true; return; }
    var req = (cls.range && Number.isFinite(Number(cls.range.min_noches))) ? Number(cls.range.min_noches) : (_DEFAULT_CAT_MIN_BIRP[cls.category] || 1);
    if (req > maxReq) maxReq = req;
  });
  if (hasStandard) maxReq = Math.max(maxReq, Number(item && item.min_noches) || 1);
  if (maxReq === 0) maxReq = Number(item && item.min_noches) || 1;
