    matched_ranges: matchedRanges,
    human_summary: humanSummary,
    fecha_inicio: String(fechaInicio).slice(0,10),
    fecha_fin: String(fechaFin).slice(0,10),
  };
}

const sanitizeListItem = (item, nights) => {
  // El toolWorkflow inyecta context_fecha_inicio/fin y personas como
  // top-level del payload (resueltos en el parent context). Cuando BIT
  // corre en sub-exec, `$('Get Context-conversations1')` no existe, así
  // que runtimeSearchCriteria queda vacío. Fallback duro al payload.
  var _sciFI = runtimeSearchCriteria.fecha_inicio || payload.context_fecha_inicio || null;
  var _sciFF = runtimeSearchCriteria.fecha_fin    || payload.context_fecha_fin    || null;
  var _sciPraw = runtimeSearchCriteria.personas || payload.context_personas || payload.personas;
  var _sciP = (_sciPraw === null || _sciPraw === undefined || _sciPraw === '') ? null : (Number(_sciPraw) || null);
  var _q = (_sciFI && _sciFF && _sciP) ? _computeQuoteBIRP(item, _sciFI, _sciFF, _sciP) : null;
  return ({
  finca_id: item.finca_id,
  codigo_original: item.codigo_original,
