  capacidad_minima: item.capacidad_minima,
  capacidad_max: item.capacidad_max,
  capacidad_minima_tarifa: item.capacidad_minima_tarifa,
  habitaciones: item.habitaciones,
  min_noches: item.min_noches,
  // ── pricing v2 (8 cols) ──
  precio_base_noche: item.precio_base_noche,
  precio_noche_base: item.precio_noche_base, // alias
  precio_persona_extra_base: item.precio_persona_extra_base,
  precio_persona_extra: item.precio_persona_extra, // alias
  precio_festivo: item.precio_festivo,
  precio_persona_extra_festivo: item.precio_persona_extra_festivo,
  precio_fin_semana: item.precio_fin_semana, // alias = festivo
  precio_semana_santa_receso: item.precio_semana_santa_receso,
  precio_persona_extra_semana_santa: item.precio_persona_extra_semana_santa,
  precio_temporada_alta: item.precio_temporada_alta,
  precio_persona_extra_temporada_alta: item.precio_persona_extra_temporada_alta,
  precio_referencia_noche: nightlyReference(item, nights),
  // ── extras v2 ──
  deposito_seguridad: item.deposito_seguridad,
  limpieza_final_valor: item.limpieza_final_valor,
  empleada_obligatorio: item.empleada_obligatorio,
  servicio_empleada_valor_8h: item.servicio_empleada_valor_8h,
  tiempo_en_vehiculo: item.tiempo_en_vehiculo,
  // ── descriptors ──
  pet_friendly: item.pet_friendly,
  amenidades: item.amenidades,
  tipo_evento: item.tipo_evento,
  descripcion_corta: item.descripcion_corta,
  privacidad: item.privacidad,
  foto_url: item.foto_url,
  owner_nombre: item.owner_nombre,
  descuento_max_pct: item.descuento_max_pct,
  prioridad: item.prioridad,
  especificacion_habitaciones: item.especificacion_habitaciones,
  observaciones_originales: item.observaciones_originales,
  quote: _q,
  });
};

const sanitizeDetailItem = (item, nights) => ({
  ...sanitizeListItem(item, nights),
  owner_contacto: ownerContactOverride || item.owner_contacto,
  administrador_nombre: item.administrador_nombre,
  administrador_contacto: item.administrador_contacto,
  review_notes: item.review_notes,
});

const uniqueValues = (values = []) => {
  const map = new Map();
  for (const value of values) {
    const trimmed = compact(value);
    const normalized = normalizeText(trimmed);
    if (!normalized || map.has(normalized)) continue;
    map.set(normalized, trimmed);
  }
  return Array.from(map.values());
};

const escapeRegExp = (value) => String(value || '').replace(/[|\\{}()[\]^$+*?.-]/g, '\\$&');
const patterniseAlias = (value) => escapeRegExp(normalizeText(value)).replace(/\s+/g, '\\s+');
const arrayFromCriteria = (value) => parseJsonArray(value).map((item) => compact(item)).filter(Boolean);

const zoneAliasDefinitions = [
  {
    keys: ['cerca a bogota', 'cerca de bogota', 'bogota y alrededores', 'bogota', 'alrededores de bogota'],
    label: 'cerca a Bogotá',
    targets: ['anapoima', 'villeta', 'la vega', 'girardot', 'carmen de apicala', 'la mesa', 'mesitas del colegio', 'ricaurte', 'melgar'],
  },
  {
    keys: ['cerca a medellin', 'cerca de medellin', 'medellin o cerca', 'medellin', 'alrededores de medellin'],
    label: 'cerca a Medellín',
    targets: ['antioquia', 'santa fe de antioquia', 'santafe de antioquia', 'guatape', 'el penol', 'san jeronimo', 'sopetran', 'barbosa', 'rionegro'],
  },
  {
    keys: ['eje cafetero', 'quindio', 'armenia', 'pereira', 'manizales', 'salento', 'filandia', 'calarca', 'risaralda', 'caldas'],
    label: 'Eje Cafetero',
    targets: ['eje cafetero', 'quindio', 'armenia', 'pereira', 'manizales', 'salento', 'filandia', 'calarca', 'risaralda', 'caldas'],
  },
];

const amenityAliasDefinitions = [
  { canonical: 'jacuzzi', aliases: ['jacuzzi', 'jacusi', 'hidromasaje'] },
  { canonical: 'piscina', aliases: ['piscina', 'pool'] },
  { canonical: 'bbq', aliases: ['bbq', 'barbecue', 'asador'] },
  { canonical: 'wifi', aliases: ['wifi', 'wi fi', 'internet'] },
  { canonical: 'parqueadero', aliases: ['parqueadero', 'garaje', 'parking'] },
  { canonical: 'kiosko', aliases: ['kiosko', 'quiosco'] },
  { canonical: 'cancha de tejo', aliases: ['tejo', 'cancha de tejo'] },
  { canonical: 'cancha de micro futbol', aliases: ['micro futbol', 'microfutbol', 'cancha de futbol', 'futbol'] },
  { canonical: 'mesa de ping pong', aliases: ['ping pong', 'mesa de ping pong'] },
  { canonical: 'mesa de billar', aliases: ['billar', 'mesa de billar', 'pool'] },
  { canonical: 'rana', aliases: ['rana'] },
  { canonical: 'zonas verdes', aliases: ['zonas verdes', 'zona verde'] },
  { canonical: 'pet friendly', aliases: ['pet friendly', 'mascotas', 'mascota'] },
  { canonical: 'servicio de empleada', aliases: ['empleada', 'servicio de empleada'] },
  { canonical: 'golf', aliases: ['golf'] },
  { canonical: 'tenis', aliases: ['tenis', 'cancha de tenis'] },
];

const resolveZoneAlias = (value) => {
  const normalizedValue = normalizeText(value);
  if (!normalizedValue) return null;
  return (
    zoneAliasDefinitions.find((alias) =>
      alias.keys.some((key) => normalizedValue.includes(key) || key.includes(normalizedValue)),
    ) || null
  );
};

const resolveLocationExpressionTargets = (value) => {
  const normalizedValue = normalizeText(value);
  if (!normalizedValue) return [];
  const alias = resolveZoneAlias(value);
  return alias ? alias.targets.map((item) => normalizeText(item)) : [normalizedValue];
};

const resolveAmenityAlias = (value) => {
  const normalizedValue = normalizeText(value);
  if (!normalizedValue) return '';
  const alias = amenityAliasDefinitions.find((entry) =>
    entry.aliases.some((candidate) => normalizedValue.includes(normalizeText(candidate))),
  );
  return alias ? alias.canonical : compact(value);
};

const negativePatternTemplates = [
  (alias) => '(?:^|\\b)(?:sin|pero\\s+sin)\\s+' + alias + '(?:\\b|$)',
  (alias) => '(?:^|\\b)(?:pero\\s+no|menos|excepto|salvo|no\\s+sea|que\\s+no\\s+sea)\\s+' + alias + '(?:\\b|$)',
  (alias) => '(?:^|\\b)(?:no\\s+quiero(?:\\s+que\\s+tenga)?|que\\s+no\\s+tenga|que\\s+no\\s+sea)\\s+' + alias + '(?:\\b|$)',
];
const clearPatternTemplates = [
  (alias) => '(?:^|\\b)(?:ya\\s+no\\s+importa(?:\\s+si\\s+tiene)?|puede\\s+tener|tambien\\s+puede\\s+tener)\\s+' + alias + '(?:\\b|$)',
  (alias) => '(?:^|\\b)' + alias + '\\s+(?:si|sí)\\s+puede\\s+ser(?:\\b|$)',
  (alias) => '(?:^|\\b)tambien\\s+puede\\s+ser\\s+' + alias + '(?:\\b|$)',
  (alias) => '(?:^|\\b)' + alias + '\\s+ya\\s+no\\s+importa(?:\\b|$)',
];

const messageMatchesPatterns = (message, aliases, templates) => {
  const normalizedMessage = normalizeText(message);
  if (!normalizedMessage) return false;
  return aliases.some((alias) => {
    const patternAlias = patterniseAlias(alias);
    return templates.some((template) => new RegExp(template(patternAlias), 'i').test(normalizedMessage));
  });
};

const detectDefinitionValuesFromMessage = (definitions, message, templates) =>
  uniqueValues(
    definitions
      .filter((definition) => messageMatchesPatterns(message, definition.aliases, templates))
      .map((definition) => definition.canonical),
  );

const opInput = normalizeText(payload.operation);
const operation = (() => {
  if (['mostrar_propiedades', 'show_properties', 'buscar_fincas', 'search_fincas', 'list_matching_fincas', 'list'].includes(opInput)) return 'list_matching_fincas';
  if (['pregunta_propiedad', 'property_question', 'finca_question', 'detalle_finca', 'get_finca_details', 'details'].includes(opInput)) return 'get_finca_details';
  if (['contacto_propietario', 'owner_contact', 'get_owner_contact'].includes(opInput)) return 'get_owner_contact';
  return 'list_matching_fincas';
})();

const explicitFincaId = compact(payload.finca_id || payload.selected_finca_id || runtimeContext.selected_finca_id || runtimeContext.selected_finca?.finca_id);
const explicitName = compact(payload.nombre || payload.selected_finca_nombre || runtimeContext.selected_finca?.nombre);
const query = compact(payload.query);
const zona = compact(payload.zona || payload.context_zona || runtimeSearchCriteria.zona);
const personas = toNumber(payload.personas || payload.context_personas || runtimeSearchCriteria.personas, null);
const presupuestoMax = toNumber(payload.presupuesto_max || payload.context_presupuesto_max || runtimeSearchCriteria.presupuesto_max, null);
const requiresPetFriendly = (() => {
  const v = payload.mascotas ?? payload.context_mascotas ?? runtimeSearchCriteria.mascotas;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'string') return ['true','si','sí','yes','1'].includes(v.trim().toLowerCase());
  return false;
})();
const requiredTipoEvento = (() => {
  const v = compact(payload.tipo_evento || payload.context_tipo_evento || runtimeSearchCriteria.tipo_evento);
  if (!v) return null;
  return normalizeText(v);
})();
const nights = calculateNights(
  payload.context_fecha_inicio || runtimeSearchCriteria.fecha_inicio,
  payload.context_fecha_fin || runtimeSearchCriteria.fecha_fin,
);
const defaultLimit = Math.max(1, Math.min(10, toNumber(settings.max_properties_to_show || settings.maxPropertiesToShow, 3) || 3));
const limit = Math.max(1, Math.min(10, toNumber(payload.limit, defaultLimit) || defaultLimit));
const normalizedMessage = normalizeText(query);
const messageRejectsCurrentSelection =
  /\b(no esa|esa no|no me gusto esa|no me gustó esa|no quiero esa|descarta esa)\b/.test(normalizedMessage);

const knownMunicipios = uniqueValues(inventory.map((item) => compact(item.municipio)).filter(Boolean));
const knownZonas = uniqueValues([
  ...inventory.map((item) => compact(item.zona)).filter(Boolean),
  ...zoneAliasDefinitions.map((item) => item.label),
]);

const criteriaAmenidadesPositivas = uniqueValues(
  arrayFromCriteria(runtimeSearchCriteria.amenidades).map((item) => resolveAmenityAlias(item) || item),
);
const criteriaAmenidadesExcluidasBase = uniqueValues(
  arrayFromCriteria(runtimeSearchCriteria.amenidades_excluidas).map((item) => resolveAmenityAlias(item) || item),
);
const criteriaZonasExcluidasBase = uniqueValues(arrayFromCriteria(runtimeSearchCriteria.zonas_excluidas));
const criteriaMunicipiosExcluidosBase = uniqueValues(arrayFromCriteria(runtimeSearchCriteria.municipios_excluidos));
const criteriaFincasExcluidasBase = uniqueValues(arrayFromCriteria(runtimeSearchCriteria.fincas_excluidas));

const messageAmenidadesExcluidas = detectDefinitionValuesFromMessage(amenityAliasDefinitions, query, negativePatternTemplates);
const messageAmenidadesPermitidas = detectDefinitionValuesFromMessage(amenityAliasDefinitions, query, clearPatternTemplates);
const messageZonasExcluidas = uniqueValues(
  knownZonas.filter((candidate) =>
    messageMatchesPatterns(query, [candidate, ...(resolveZoneAlias(candidate)?.keys || [])], negativePatternTemplates),
  ),
);
const messageZonasPermitidas = uniqueValues(
  knownZonas.filter((candidate) =>
    messageMatchesPatterns(query, [candidate, ...(resolveZoneAlias(candidate)?.keys || [])], clearPatternTemplates),
  ),
);
const messageMunicipiosExcluidos = uniqueValues(
  knownMunicipios.filter((candidate) => messageMatchesPatterns(query, [candidate], negativePatternTemplates)),
);
const messageMunicipiosPermitidos = uniqueValues(
  knownMunicipios.filter((candidate) => messageMatchesPatterns(query, [candidate], clearPatternTemplates)),
);

const amenidadesExcluidas = uniqueValues([
  ...criteriaAmenidadesExcluidasBase.filter(
    (item) => !messageAmenidadesPermitidas.some((allowed) => normalizeText(allowed) === normalizeText(item)),
  ),
  ...messageAmenidadesExcluidas,
]);
const zonasExcluidas = uniqueValues([
  ...criteriaZonasExcluidasBase.filter(
    (item) => !messageZonasPermitidas.some((allowed) => normalizeText(allowed) === normalizeText(item)),
  ),
  ...messageZonasExcluidas,
]);
const municipiosExcluidos = uniqueValues([
  ...criteriaMunicipiosExcluidosBase.filter(
    (item) => !messageMunicipiosPermitidos.some((allowed) => normalizeText(allowed) === normalizeText(item)),
  ),
  ...messageMunicipiosExcluidos,
]);
const fincasExcluidas = uniqueValues([
  ...criteriaFincasExcluidasBase,
  ...inferFincaIdsFromText([query, explicitFincaId, explicitName].filter(Boolean).join(' ')),
  ...(messageRejectsCurrentSelection ? [explicitFincaId].filter(Boolean) : []),
]);

const shownFincas = new Set(
  [
    ...parseJsonArray(payload.shown_fincas_json || JSON.stringify(runtimeContext.shown_fincas || [])),
    ...fincasExcluidas,
  ].map((item) => String(item)),
);

const negativeTokens = new Set(
  tokenise(
    [
      ...amenidadesExcluidas,
      ...zonasExcluidas,
      ...municipiosExcluidos,
      ...fincasExcluidas,
    ].join(' '),
  ),
);
const positiveTokens = tokenise([query, explicitName, explicitFincaId, zona, ...criteriaAmenidadesPositivas].filter(Boolean).join(' '))
  .filter((token) => !negativeTokens.has(token));

const resolvedZoneAlias = resolveZoneAlias(zona);
const zoneTargets = resolvedZoneAlias
  ? resolvedZoneAlias.targets.map((item) => normalizeText(item))
  : zona
    ? [normalizeText(zona)]
    : [];
const excludedLocationTargets = uniqueValues(
  [...zonasExcluidas, ...municipiosExcluidos].flatMap((item) => resolveLocationExpressionTargets(item)),
).map((item) => normalizeText(item));
const preferredAmenityTargets = new Set(
  uniqueValues(criteriaAmenidadesPositivas.map((item) => resolveAmenityAlias(item) || item)).map((item) => normalizeText(item)),
);
const excludedAmenityTargets = new Set(
  uniqueValues(amenidadesExcluidas.map((item) => resolveAmenityAlias(item) || item)).map((item) => normalizeText(item)),
);
const excludedFincaTargets = new Set(fincasExcluidas.map((item) => normalizeText(item)));

const locationMatchesTargets = (item, targets) => {
  // Returns 'strong' (zona/municipio explicitly contains the target),
  //         'weak'   (only the empty-municipio fallback matched — broad-zone finca),
  //         null     (no match at all).
  // Strict candidates only accept 'strong'. Similar candidates accept both.
  if (!targets.length) return null;
  const itemZona = normalizeText(item.zona);
  const itemMunicipio = normalizeText(item.municipio);
  let best = null;
  for (const target of targets) {
    if (!target) continue;
    if (itemZona && (itemZona.includes(target) || target.includes(itemZona))) return 'strong';
    if (itemMunicipio && (itemMunicipio.includes(target) || target.includes(itemMunicipio))) return 'strong';
    // weak fallback: finca has empty zona OR empty municipio (broad-zone listing)
    if ((!itemZona || !itemMunicipio) && (target.includes(itemZona) || target.includes(itemMunicipio))) {
      best = best || 'weak';
    }
  }
  return best;
};

const zoneMatches = (item) => {
  if (!zoneTargets.length) return 'strong';
  return locationMatchesTargets(item, zoneTargets);
};

const itemAmenityTargets = (item) =>
  new Set(
    uniqueValues(
      (Array.isArray(item.amenidades) ? item.amenidades : []).map((entry) => resolveAmenityAlias(entry) || entry),
    ).map((entry) => normalizeText(entry)),
  );

const matchesExcludedLocation = (item) =>
  excludedLocationTargets.length ? locationMatchesTargets(item, excludedLocationTargets) : false;
const matchesExcludedFinca = (item) => {
  if (!excludedFincaTargets.size) return false;
  return (
    excludedFincaTargets.has(normalizeText(item.finca_id)) ||
    excludedFincaTargets.has(normalizeText(item.nombre)) ||
    excludedFincaTargets.has(normalizeText(item.codigo_original))
  );
};
const itemHasExcludedAmenity = (item) => {
  if (!excludedAmenityTargets.size) return false;
  const amenityTargets = itemAmenityTargets(item);
  return Array.from(excludedAmenityTargets).some((target) => amenityTargets.has(target));
};
const countPreferredAmenities = (item) => {
  if (!preferredAmenityTargets.size) return 0;
  const amenityTargets = itemAmenityTargets(item);
  return Array.from(preferredAmenityTargets).filter((target) => amenityTargets.has(target)).length;
};

const scoreItem = (item, strict) => {
  let score = 0;
  if (explicitFincaId && normalizeText(item.finca_id) === normalizeText(explicitFincaId)) score += 1000;
  if (explicitName && normalizeText(item.nombre).includes(normalizeText(explicitName))) score += 280;
  if (zona) {
    const zm = zoneMatches(item);
    if (zm === 'strong') score += strict ? 160 : 120;
    else if (zm === 'weak') score += strict ? -200 : -50; // weak: heavy penalty in strict, mild in similar
    else score -= strict ? 600 : 120;
  }
  if (personas !== null && item.capacidad_max !== null) {
    if (item.capacidad_max < personas) {
      score -= strict ? 800 : 180;
    } else {
      // Capacity-fit: prefer fincas where the group size is close to
      // (or just below) capacidad_max, and to capacidad_minima too —
      // because the base rate is set for cap_min, paying base for a
      // group much smaller than cap_min is bad value for the customer.
      score += 100;
      const oversizeMax = Math.max(0, item.capacidad_max - personas);
      score -= oversizeMax * 5; // 5pts per extra slot above the group
      const capMin = Number(item.capacidad_minima) || 0;
      if (capMin > 0) {
        const oversizeMin = Math.max(0, capMin - personas);
        score -= oversizeMin * 10; // bigger penalty: paying base for unused capacity
      }
    }
  }
  if (nights !== null && item.min_noches !== null) {
    if (item.min_noches <= nights) score += 20;
    else score -= strict ? 120 : 40;
  }
  if (presupuestoMax !== null) {
    const refPrice = nightlyReference(item, nights);
    if (refPrice !== null) {
      const delta = Math.abs(refPrice - presupuestoMax);
      const deltaRatio = presupuestoMax > 0 ? delta / presupuestoMax : 0;
      score += Math.max(0, 90 - deltaRatio * 110);
      if (refPrice <= presupuestoMax) score += 25;
      else score -= Math.min(50, deltaRatio * 70);
    }
  }
  const preferredAmenityMatches = countPreferredAmenities(item);
  if (preferredAmenityMatches > 0) {
    score += preferredAmenityMatches * 28;
  }
  if (positiveTokens.length) {
    const haystack = normalizeText([
      item.finca_id,
      item.nombre,
      item.codigo_original,
      item.zona,
      item.municipio,
      item.descripcion_corta,
      item.observaciones_originales,
      item.caracteristicas_originales,
      (item.amenidades || []).join(' '),
      (item.tipo_evento || []).join(' '),
    ].filter(Boolean).join(' '));
    for (const token of positiveTokens) {
      if (haystack.includes(token)) score += 16;
    }
  }
  // prioridad: only tiers 1-3 carry weight, with significant gaps.
  // Sheet uses 1=top. Anything else (null, 4+) gets 0 — out of the
  // 'preferred catalog' band, doesn't get a thumb on the scale.
  const prio = Number(item.prioridad);
  if (prio === 1) score += 80;
  else if (prio === 2) score += 40;
  else if (prio === 3) score += 15;
  return score;
};

const ranked = (items, strict) =>
  items
    .map((item) => ({ item, score: scoreItem(item, strict) }))
    .sort(
      (a, b) =>
        b.score - a.score ||
        Number(a.item.prioridad || 999) - Number(b.item.prioridad || 999) ||
        String(a.item.nombre).localeCompare(String(b.item.nombre)),
    )
    .map(({ item }) => item);

const strictCandidates = inventory.filter((item) => {
  if (zoneMatches(item) !== 'strong') return false;
  if (personas !== null && item.capacidad_max !== null && item.capacidad_max < personas) return false;
  if (matchesExcludedLocation(item)) return false;
  if (matchesExcludedFinca(item)) return false;
  if (itemHasExcludedAmenity(item)) return false;
  // === NEW FILTERS (Sheet v2: min_noches date-aware, pet_friendly, tipo_evento) ===
  if (nights !== null) {
    var _fi = payload.context_fecha_inicio || runtimeSearchCriteria.fecha_inicio;
    var _ff = payload.context_fecha_fin   || runtimeSearchCriteria.fecha_fin;
    var _eff = (_fi && _ff) ? _effectiveMinNochesBIRP(item, _fi, _ff) : (Number.isFinite(item.min_noches) ? item.min_noches : 1);
    if (_eff > nights) return false;
    // fechas_no_disponibles: hard exclusion when booking overlaps a blocked range
    if (_fi && _ff && _bookingOverlapsUnavailable(item, _fi, _ff)) return false;
  }
  if (requiresPetFriendly && item.pet_friendly !== true) return false;
  if (requiredTipoEvento) {
    const tipos = (Array.isArray(item.tipo_evento) ? item.tipo_evento : []).map((t) => normalizeText(t));
    if (!tipos.some((t) => t.includes(requiredTipoEvento) || requiredTipoEvento.includes(t))) return false;
  }
  return true;
});

const similarCandidates = inventory.filter((item) => {
  if (shownFincas.has(String(item.finca_id))) return false;
  if (matchesExcludedLocation(item)) return false;
  if (matchesExcludedFinca(item)) return false;
  if (itemHasExcludedAmenity(item)) return false;
  if (zona && !zoneMatches(item) && personas !== null && item.capacidad_max !== null && item.capacidad_max < personas) {
    return false;
  }
  return true;
});

const strictRanked = ranked(strictCandidates, true).filter((item) => !shownFincas.has(String(item.finca_id)));
const similarRanked = ranked(similarCandidates, false).filter((item) => !shownFincas.has(String(item.finca_id)));

const buildErrorResponse = () => [
  {
    json: {
      operation,
      error: true,
      matched_count: 0,
      items: [],
      similar_items: [],
      selected_finca: null,
      owner: null,
      search_applied: {
        zona,
        personas,
        presupuesto_max: presupuestoMax,
        nights,
        amenidades_preferidas: criteriaAmenidadesPositivas,
        amenidades_excluidas: amenidadesExcluidas,
        zonas_excluidas: zonasExcluidas,
        municipios_excluidos: municipiosExcluidos,
        fincas_excluidas: fincasExcluidas,
        query,
