const parseCsv = (text) => {
  const rows = [];
  let row = [];
  let cell = '';
  let index = 0;
  let inQuotes = false;
  const source = String(text || '').replace(/^\uFEFF/, '');

  while (index < source.length) {
    const char = source[index];

    if (inQuotes) {
      if (char === '"') {
        if (source[index + 1] === '"') {
          cell += '"';
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }

      cell += char;
      index += 1;
      continue;
    }

    if (char === '"') {
      inQuotes = true;
      index += 1;
      continue;
    }

    if (char === ',') {
      row.push(cell);
      cell = '';
      index += 1;
      continue;
    }

    if (char === '\r') {
      index += 1;
      continue;
    }

    if (char === '\n') {
      row.push(cell);
      rows.push(row);
      row = [];
      cell = '';
      index += 1;
      continue;
    }

    cell += char;
    index += 1;
  }

  row.push(cell);
  if (row.length > 1 || compact(row[0])) {
    rows.push(row);
  }

  return rows;
};

