function stripCodeFences(str) {
  if (!str) return '';
  return String(str).trim()
    .replace(/^\s*\`\`\`json\s*/i, '')
    .replace(/^\s*\`\`\`\s*/i, '')
    .replace(/\s*\`\`\`\s*$/i, '')
    .trim();
}

function extractFirstJsonObject(text) {
  const s = String(text || '');
  const start = s.search(/[\[{]/);
  if (start === -1) return null;
  const open = s[start];
  const close = open === '{' ? '}' : ']';
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < s.length; i++) {
    const ch = s[i];
    if (inString) { if (escape) escape = false; else if (ch === '\\') escape = true; else if (ch === '"') inString = false; continue; }
    if (ch === '"') { inString = true; continue; }
    if (ch === open) depth++; else if (ch === close) { depth--; if (depth === 0) return s.slice(start, i + 1); }
  }
  return null;
}

function safeParse(text) {
  if (text == null) return null;
  const raw = String(text).trim();
  try { return JSON.parse(raw); } catch {
    const candidate = extractFirstJsonObject(stripCodeFences(raw));
    if (!candidate) return { _raw: raw.slice(0, 12000) };
    try { return JSON.parse(candidate); } catch { return { _raw: raw.slice(0, 12000) }; }
  }
}

const rawOutput = typeof $json.output === 'string' ? $json.output
  : Array.isArray($json.output) && typeof $json.output[0]?.output === 'string' ? $json.output[0].output : '';

const toolOutput = safeParse(stripCodeFences(rawOutput || '')) || {};
const currentState = $('Compute deterministic prechecks').item.json.effective_state || $('Get Context-conversations1').item.json.current_state || 'CONFIRMING_RESERVATION';

return [{
  json: {
    output: JSON.stringify({
      action: toolOutput?.intent === 'HITL_REQUEST' ? 'HITL' : 'RUN_TOOL',
      tool_chosen: 'confirming_reservation_agent',
      tool_output: toolOutput,
      post_actions: {},
      final_whatsapp_text: typeof toolOutput?.respuesta === 'string' ? toolOutput.respuesta : null,
      current_state_changed: false,
    }),
  },
}];

const compact = (v) => String(v ?? '').trim();
const source = compact($('Normalize inbound payload').item.json.source);
const waMessageId = compact($('Normalize inbound payload').item.json.wa_message_id);

// Only for real Chatwoot messages with a valid wamid
if (source !== 'simulator' && waMessageId && waMessageId.startsWith('wamid.')) {
  try {
    await this.helpers.httpRequest({
      url: 'https://graph.facebook.com/v21.0/1170778729444650/messages',
      method: 'POST',
      headers: {
        Authorization: 'Bearer EAAZA467YgZBEQBRLScZAfftZAPMFdNIcWVeNNj3vPP6Y88ILNvISorwSxQD2Owvfas4nX0u9EM4ngH9UAHWZBzE61zm8Fhnz9ASN12uOjNYskDZAMXJeDyrbPmdomRhPllsJHVDdqCCFZBpCf5ZCUl8MbXP9iK7YEZBZAmFdz7lz2wG4jyhyptCMdLmqmIbLmQWpDpZAAZDZD',
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        status: 'read',
        message_id: waMessageId,
        typing_indicator: { type: 'text' },
      }),
      timeout: 5000,
      ignoreHttpStatusErrors: true,
    });
  } catch {}
}
return $input.all();

const orig = $('Normalize inbound payload').item.json || {};
const repliedId = orig.replied_to_chatwoot_message_id;

// Postgres lookup result (finca match)
let finca = null;
let kind = null;
try {
  const pgRow = $('Resolve replied finca').first().json;
  if (pgRow && pgRow.finca_id) { finca = String(pgRow.finca_id); kind = String(pgRow.message_kind || ''); }
} catch (e) {}

// Chatwoot snippet — find the original message by id in the list returned by HTTP
let originalSnippet = null;
let originalMessageType = null;
let originalAttachmentTypes = null;
try {
  const cwResp = $('Fetch chatwoot messages for reply').first().json;
  const list = (cwResp && (cwResp.payload || cwResp.data?.payload || cwResp.data || [])) || [];
  if (Array.isArray(list) && repliedId) {
    const found = list.find((m) => String(m && m.id) === String(repliedId));
    if (found) {
      originalSnippet = String(found.content || '').slice(0, 280);
      originalMessageType = found.message_type === 1 || found.message_type === 'outgoing' ? 'bot' : 'user';
      const att = Array.isArray(found.attachments) ? found.attachments : [];
      if (att.length) originalAttachmentTypes = att.map((a) => a.file_type).filter(Boolean);
    }
  }
} catch (e) {}

return [
  {
    json: {
      ...orig,
      replied_to_finca_id: finca,
      replied_to_message_kind: kind,
      replied_to_original_text: originalSnippet,
      replied_to_original_sender: originalMessageType,
      replied_to_original_attachments: originalAttachmentTypes,
    },
  },
];

// OpenAI Whisper multipart needs a filename for the `file` part. The
// Chatwoot attachment download lacks Content-Disposition, so binary.data
// arrives with fileName=null and OpenAI refuses with 400 'Expected UploadFile'.
const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    if (!item.binary.data.fileName) {
      const mt = String(item.binary.data.mimeType || 'audio/ogg').toLowerCase();
      let ext = 'ogg';
      if (mt.includes('mpeg')) ext = 'mp3';
      else if (mt.includes('mp4') || mt.includes('m4a')) ext = 'm4a';
      else if (mt.includes('wav')) ext = 'wav';
      else if (mt.includes('webm')) ext = 'webm';
      else if (mt.includes('opus') || mt.includes('ogg')) ext = 'ogg';
      const fromInput = String(item.json?.audio_filename || '').trim();
      item.binary.data.fileName = fromInput || ('audio.' + ext);
    }
  }
}
return items;

// Re-emite el output de BIT para que el toolWorkflow devuelva
// al LLM exactamente lo que BIT computó (con quote per-item),
// no el resultado del UPDATE de Postgres.
return $('Build Inventory Tool Response').all();

