function stripCodeFences(str) {
  if (!str) return '';
  return String(str)
    .trim()
    .replace(/^\s*\`\`\`json\s*/i, '')
    .replace(/^\s*\`\`\`\s*/i, '')
    .replace(/\s*\`\`\`\s*$/i, '')
    .trim();
}

function extractFirstJsonObject(text) {
  const s = String(text || '');
  const start = s.indexOf('{');
  if (start === -1) return null;
  let depth = 0;
  let inString = false;
  let escape = false;

  for (let i = start; i < s.length; i++) {
    const ch = s[i];
    if (inString) {
      if (escape) escape = false;
      else if (ch === '\\') escape = true;
      else if (ch === '"') inString = false;
    } else {
      if (ch === '"') inString = true;
      else if (ch === '{') depth++;
      else if (ch === '}') depth--;
      if (depth === 0) return s.slice(start, i + 1);
    }
  }

  return null;
}

function escapeControlCharsInsideStrings(jsonLike) {
  const s = String(jsonLike || '');
  let out = '';
  let inString = false;
  let escape = false;

  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    const code = ch.charCodeAt(0);

    if (inString) {
      if (escape) {
        out += ch;
        escape = false;
        continue;
      }
      if (ch === '\\') {
        out += ch;
        escape = true;
        continue;
      }
      if (ch === '"') {
        out += ch;
        inString = false;
        continue;
      }
      if (ch === '\n') {
        out += '\\n';
        continue;
      }
      if (ch === '\r') {
        out += '\\r';
        continue;
      }
      if (ch === '\t') {
        out += '\\t';
        continue;
      }
      if (code >= 0x00 && code <= 0x1f) {
        out += '\\u' + code.toString(16).padStart(4, '0');
        continue;
      }
    }

    if (ch === '"') inString = true;
    out += ch;
  }

  return out;
}

function safeParse(text) {
  if (text == null) return null;
  const cleaned = escapeControlCharsInsideStrings(String(text).trim());
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const obj = extractFirstJsonObject(cleaned);
    if (!obj) return { _raw: cleaned.slice(0, 12000), _parse_error: error.message };
    try {
      return JSON.parse(obj);
    } catch (innerError) {
      return { _raw: cleaned.slice(0, 12000), _parse_error: innerError.message };
    }
  }
}

function extractJsonValueByKey(text, key) {
  const source = String(text || '');
  const keyIndex = source.indexOf(`"${key}"`);
  if (keyIndex === -1) return null;

  let cursor = keyIndex + key.length + 2;
  while (cursor < source.length && source[cursor] !== ':') cursor += 1;
  if (cursor >= source.length) return null;
  cursor += 1;
  while (cursor < source.length && /\s/.test(source[cursor])) cursor += 1;
  if (cursor >= source.length) return null;

  const start = cursor;
  const first = source[start];

  if (first === '"') {
    let escape = false;
    for (let i = start + 1; i < source.length; i += 1) {
      const char = source[i];
      if (escape) {
        escape = false;
        continue;
      }
      if (char === '\\') {
        escape = true;
        continue;
      }
      if (char === '"') return source.slice(start, i + 1);
    }
    return source.slice(start);
  }

  if (first === '{' || first === '[') {
    const open = first;
    const close = first === '{' ? '}' : ']';
    let depth = 0;
    let inString = false;
    let escape = false;

    for (let i = start; i < source.length; i += 1) {
      const char = source[i];
      if (inString) {
        if (escape) escape = false;
        else if (char === '\\') escape = true;
        else if (char === '"') inString = false;
        continue;
      }
      if (char === '"') {
        inString = true;
        continue;
      }
      if (char === open) depth += 1;
      else if (char === close) {
        depth -= 1;
        if (depth === 0) return source.slice(start, i + 1);
      }
    }
    return source.slice(start);
  }

  let end = start;
  while (end < source.length && ![',', '\n', '\r', '}'].includes(source[end])) end += 1;
  return source.slice(start, end).trim();
}

function salvageParsedFromRaw(text) {
  const raw = String(text || '');
  return {
    action: safeParse(extractJsonValueByKey(raw, 'action')) || 'RUN_TOOL',
    tool_chosen: safeParse(extractJsonValueByKey(raw, 'tool_chosen')) || 'NONE',
    tool_output: safeParse(extractJsonValueByKey(raw, 'tool_output')),
    post_actions: safeParse(extractJsonValueByKey(raw, 'post_actions')) || {},
    final_whatsapp_text: safeParse(extractJsonValueByKey(raw, 'final_whatsapp_text')),
    current_state_changed: safeParse(extractJsonValueByKey(raw, 'current_state_changed')) === true,
  };
}

function parseToolOutput(parsed) {
  const toolOutput = parsed?.tool_output;
  if (!toolOutput || typeof toolOutput !== 'object') return null;

  if (Array.isArray(toolOutput)) {
    if (typeof toolOutput[0]?.output === 'string') {
      return safeParse(stripCodeFences(toolOutput[0].output));
    }
    if (typeof toolOutput[0]?.result === 'string') {
      return safeParse(stripCodeFences(toolOutput[0].result));
    }
    return toolOutput[0] && typeof toolOutput[0] === 'object' ? toolOutput[0] : toolOutput;
  }

  let rawResult = null;

  if (typeof toolOutput.result === 'string') {
    rawResult = toolOutput.result;
  } else {
    const firstKey = Object.keys(toolOutput)[0];
    if (firstKey && toolOutput[firstKey] && typeof toolOutput[firstKey].result === 'string') {
      rawResult = toolOutput[firstKey].result;
    } else if (firstKey && toolOutput[firstKey] && typeof toolOutput[firstKey].output === 'string') {
      rawResult = toolOutput[firstKey].output;
    }
  }

  if (!rawResult) return toolOutput;

  const firstPass = safeParse(rawResult);
  if (Array.isArray(firstPass) && firstPass[0]?.output) {
    return safeParse(stripCodeFences(firstPass[0].output));
  }
  return firstPass;
}

function normalizeBoolean(value) {
  if (typeof value === 'boolean') return value;
  if (value === null || value === undefined || value === '') return false;
  return ['true', '1', 'yes', 'si', 'sí'].includes(String(value).trim().toLowerCase());
}

function compactCriteria(source = {}) {
  const clearableArrayKeys = new Set([
    'amenidades',
    'amenidades_excluidas',
    'zonas_excluidas',
    'municipios_excluidos',
    'fincas_excluidas',
  ]);
  const out = {};
  for (const [key, value] of Object.entries(source || {})) {
    if (value === undefined || value === null) continue;
    if (Array.isArray(value) && value.length === 0 && !clearableArrayKeys.has(key)) continue;
    if (typeof value === 'string' && value.trim() === '') continue;
    out[key] = value;
  }
  return out;
}

function normalizeCriteriaEntry(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

function uniqueCriteriaArray(values = []) {
  const map = new Map();
  for (const value of values) {
    const trimmed = String(value || '').trim();
    const normalized = normalizeCriteriaEntry(trimmed);
    if (!normalized || map.has(normalized)) continue;
    map.set(normalized, trimmed);
  }
  return Array.from(map.values());
}

function mergeCriteriaWithCurrent(source = {}) {
  const currentSearchCriteria =
    $('Get Context-conversations1').item.json.search_criteria ||
    $('Get Context-conversations1').item.json.context?.search_criteria ||
    {};
  const unionKeys = new Set([
    'amenidades_excluidas',
    'zonas_excluidas',
    'municipios_excluidos',
    'fincas_excluidas',
  ]);
  const merged = { ...source };

  for (const key of unionKeys) {
    if (!(key in merged) || !Array.isArray(merged[key])) continue;
    if (merged[key].length === 0) {
      merged[key] = [];
      continue;
    }
    const currentValues = Array.isArray(currentSearchCriteria?.[key]) ? currentSearchCriteria[key] : [];
    merged[key] = uniqueCriteriaArray([...currentValues, ...merged[key]]);
  }

  return compactCriteria(merged);
}

function normalizePostActions(parsed, toolOutput) {
  const raw = parsed?.post_actions && typeof parsed.post_actions === 'object' ? { ...parsed.post_actions } : {};
  const tool = parsed?.tool_chosen || 'NONE';
  const intent = toolOutput?.intent || null;
  const currentContext = $('Get Context-conversations1').item.json || {};
  const currentExtras = currentContext.extras || currentContext.context?.extras || {};
  const currentConfirmation =
    currentExtras.confirming_reservation && typeof currentExtras.confirming_reservation === 'object'
      ? currentExtras.confirming_reservation
      : {};
  const currentConfirmationVersion = Number(
    currentContext.confirmacion_version || currentContext.context?.confirmacion?.version || 0,
  );

  if (tool === 'qualifying_agent') {
    const extraidos = compactCriteria(toolOutput?.datos_extraidos || {});
    if (Object.keys(extraidos).length && !raw.search_criteria) raw.search_criteria = extraidos;
    if (toolOutput?.datos_completos === true && !raw.state_transition) raw.state_transition = 'OFFERING';
    if (toolOutput?.datos_completos === true && !raw.waiting_for) raw.waiting_for = 'CLIENT';
  }

  if (tool === 'offering_agent') {
    if (Array.isArray(toolOutput?.fincas_mostradas) && !raw.shown_fincas) {
      raw.shown_fincas = toolOutput.fincas_mostradas
        .map((item) => item?.finca_id || item?.id || null)
        .filter(Boolean);
    }
    if (toolOutput?.search_criteria_update && !raw.search_criteria) raw.search_criteria = compactCriteria(toolOutput.search_criteria_update);
    if (toolOutput?.intent === 'CLIENT_CHOSE') {
      // Skip visible 'verifying availability' step. The owner gets
      // notified in parallel by the selection_notification flow.
      // The bot proceeds straight to data collection (CONFIRMING).
      raw.state_transition ||= 'CONFIRMING_RESERVATION';
      raw.selected_finca_id ||= toolOutput.finca_elegida_id || toolOutput.selected_finca?.finca_id || '__IGNORE__';
      raw.selected_finca ||= toolOutput.selected_finca || '__IGNORE__';
      raw.waiting_for ||= 'CLIENT';
    }
  }

  if (tool === 'verifying_availability_agent') {
    if (toolOutput?.selected_finca && !raw.selected_finca) raw.selected_finca = toolOutput.selected_finca;
    if ((toolOutput?.finca_elegida_id || toolOutput?.selected_finca?.finca_id) && !raw.selected_finca_id) {
      raw.selected_finca_id = toolOutput.finca_elegida_id || toolOutput.selected_finca?.finca_id;
    }
    if (intent === 'CHANGE_FINCA') {
      raw.state_transition ||= 'OFFERING';
      raw.waiting_for ||= 'CLIENT';
      raw.selected_finca_id ||= '__CLEAR__';
      raw.selected_finca ||= '__CLEAR__';
    }
    // Auto-transition to CONFIRMING_RESERVATION after verifying message
    if (!raw.state_transition || raw.state_transition === '__IGNORE__') {
      if (intent !== 'CHANGE_FINCA' && intent !== 'HITL_REQUEST') {
        raw.state_transition = 'CONFIRMING_RESERVATION';
        raw.waiting_for = 'CLIENT';
        raw.loop_reason = 'state_transition';
      }
    }
  }

  if (tool === 'confirming_reservation_agent') {
    if (toolOutput?.selected_finca && !raw.selected_finca) raw.selected_finca = toolOutput.selected_finca;
    if ((toolOutput?.finca_elegida_id || toolOutput?.selected_finca?.finca_id) && !raw.selected_finca_id) {
      raw.selected_finca_id = toolOutput.finca_elegida_id || toolOutput.selected_finca?.finca_id;
    }

    const isPlainObj = (v) => Boolean(v) && typeof v === 'object' && !Array.isArray(v);
    const mergePlain = (base, patch) => {
      const o = isPlainObj(base) ? { ...base } : {};
      for (const [k, v] of Object.entries(patch || {})) {
        if (v === undefined || v === null) continue;
        o[k] = isPlainObj(v) && isPlainObj(o[k]) ? mergePlain(o[k], v) : v;
      }
      return o;
    };
    const compactObj = (v) => {
      const o = {};
      for (const [k, e] of Object.entries(v || {})) {
        if (e != null && String(e).trim() !== '') o[k] = e;
      }
      return o;
    };

    const confirmationUpdate = compactObj(toolOutput?.confirmation_data_update || {});
    // Sanitize celular: VARCHAR(10) en DB. El LLM a veces sustituye 'este
    // mismo' con el wa_id (12 dígitos con país) o agrega '+57 ...' formats.
    // Tomar últimos 10 dígitos (formato local Colombia). Si quedan 0
    // dígitos (ej. literal 'este mismo'), borrar el campo y dejar que el
    // sistema use Merge Sets1.conversation_key como fallback.
    if (confirmationUpdate.celular !== undefined) {
      const digits = String(confirmationUpdate.celular || '').replace(/\D+/g, '');
      const last10 = digits.length >= 10 ? digits.slice(-10) : digits;
      if (last10.length === 10) confirmationUpdate.celular = last10;
      else delete confirmationUpdate.celular;
    }
    // Sanitize numero_documento: keep only digits/letters, max 20.
    if (confirmationUpdate.numero_documento) {
      confirmationUpdate.numero_documento = String(confirmationUpdate.numero_documento)
        .replace(/[^A-Za-z0-9]/g, '').slice(0, 20);
    }
    // Sanitize tipo_documento: uppercase, ASCII letters only, max 5.
    if (confirmationUpdate.tipo_documento) {
      confirmationUpdate.tipo_documento = String(confirmationUpdate.tipo_documento)
        .replace(/[^A-Za-z]/g, '').toUpperCase().slice(0, 5);
    }
    if (Object.keys(confirmationUpdate).length) {
      raw.extras = mergePlain(currentExtras, {
        confirming_reservation: mergePlain(currentConfirmation, {
          ...confirmationUpdate,
          updated_at: new Date().toISOString(),
        }),
      });
    }

    if (intent === 'DOCUMENT_READY') {
      raw.extras = mergePlain(currentExtras, {
        confirming_reservation: mergePlain(currentConfirmation, {
          ...confirmationUpdate,
          updated_at: new Date().toISOString(),
          document_ready: true,
          document_ready_at: new Date().toISOString(),
        }),
      });
      if (raw.confirmacion_enviada === undefined) raw.confirmacion_enviada = true;
      if (raw.confirmacion_version === undefined) raw.confirmacion_version = currentConfirmationVersion + 1;
      if (raw.huespedes_completos === undefined) raw.huespedes_completos = true;
      // keep agent active so the bot can still receive the "ok" approval
      raw.waiting_for ||= 'CLIENT_APPROVAL';
    }

    if (intent === 'RESERVATION_APPROVED') {
      raw.extras = mergePlain(currentExtras, {
        confirming_reservation: mergePlain(currentConfirmation, {
          ...confirmationUpdate,
          updated_at: new Date().toISOString(),
          approved: true,
          approved_at: new Date().toISOString(),
        }),
      });
      raw.confirmacion_aceptada = true;
      raw.state_transition ||= 'HITL';
      raw.waiting_for ||= 'HUMAN_HANDOFF';
      raw.agente_activo = false;
      raw.hitl_reason ||= 'reservation_approved';
    }

    if (intent === 'CHANGE_FINCA') {
      raw.state_transition ||= 'OFFERING';
      raw.waiting_for ||= 'CLIENT';
      raw.selected_finca_id ||= '__CLEAR__';
      raw.selected_finca ||= '__CLEAR__';
    }
  }

  if (tool === 'qa_agent') {
    if (toolOutput?.search_criteria_update && !raw.search_criteria) {
      raw.search_criteria = compactCriteria(toolOutput.search_criteria_update);
    }
    if (toolOutput?.selected_finca && !raw.selected_finca) raw.selected_finca = toolOutput.selected_finca;
    if ((toolOutput?.finca_elegida_id || toolOutput?.selected_finca?.finca_id) && !raw.selected_finca_id) {
      raw.selected_finca_id = toolOutput.finca_elegida_id || toolOutput.selected_finca?.finca_id;
    }
  }

  if ((parsed?.action === 'HITL' || intent === 'HITL_REQUEST') && raw.agente_activo === undefined) {
    raw.agente_activo = false;
  }

  if (parsed?.action === 'NOOP_BOT_DISABLED' && raw.agente_activo === undefined) {
    raw.agente_activo = false;
  }

  const normalized = {
    state_transition:
      typeof raw.state_transition === 'string' && raw.state_transition.trim()
        ? raw.state_transition
        : '__IGNORE__',
    search_criteria:
      raw.search_criteria && typeof raw.search_criteria === 'object'
        ? mergeCriteriaWithCurrent(raw.search_criteria)
        : '__IGNORE__',
    waiting_for:
      typeof raw.waiting_for === 'string' && raw.waiting_for.trim() ? raw.waiting_for : '__IGNORE__',
    agente_activo:
      typeof raw.agente_activo === 'boolean' ? raw.agente_activo : '__IGNORE__',
    shown_fincas: Array.isArray(raw.shown_fincas) ? raw.shown_fincas : '__IGNORE__',
    selected_finca_id:
      raw.selected_finca_id === '__CLEAR__'
        ? '__CLEAR__'
        : typeof raw.selected_finca_id === 'string' && raw.selected_finca_id.trim()
          ? raw.selected_finca_id
          : '__IGNORE__',
    selected_finca:
      raw.selected_finca === '__CLEAR__'
        ? '__CLEAR__'
        : raw.selected_finca && typeof raw.selected_finca === 'object'
          ? raw.selected_finca
          : '__IGNORE__',
    owner_response:
      raw.owner_response === '__CLEAR__'
        ? '__CLEAR__'
        : raw.owner_response && typeof raw.owner_response === 'object'
          ? raw.owner_response
          : '__IGNORE__',
    pricing:
      raw.pricing && typeof raw.pricing === 'object' && !Array.isArray(raw.pricing) ? raw.pricing : '__IGNORE__',
    extras:
      raw.extras && typeof raw.extras === 'object' && !Array.isArray(raw.extras) ? raw.extras : '__IGNORE__',
    hitl_reason:
      raw.hitl_reason === '__CLEAR__'
        ? '__CLEAR__'
        : typeof raw.hitl_reason === 'string' && raw.hitl_reason.trim()
          ? raw.hitl_reason
          : '__IGNORE__',
    confirmacion_enviada:
      typeof raw.confirmacion_enviada === 'boolean' ? raw.confirmacion_enviada : '__IGNORE__',
    confirmacion_version:
      Number.isFinite(Number(raw.confirmacion_version)) ? Math.max(0, Math.trunc(Number(raw.confirmacion_version))) : '__IGNORE__',
    huespedes_completos:
      typeof raw.huespedes_completos === 'boolean' ? raw.huespedes_completos : '__IGNORE__',
    resume_after_qa: raw.resume_after_qa === true,
    resume_state_after_qa:
      typeof raw.resume_state_after_qa === 'string' && raw.resume_state_after_qa.trim()
        ? raw.resume_state_after_qa
        : '__IGNORE__',
    loop_reason:
      typeof raw.loop_reason === 'string' && raw.loop_reason.trim()
        ? raw.loop_reason
        : '__IGNORE__',
  };

  if (normalized.search_criteria !== '__IGNORE__' && Object.keys(normalized.search_criteria).length === 0) {
    normalized.search_criteria = '__IGNORE__';
  }

  return normalized;
}

function getRawOutput(itemJson) {
  if (typeof itemJson?.output === 'string') return itemJson.output;
  if (Array.isArray(itemJson?.output) && typeof itemJson.output[0]?.output === 'string') return itemJson.output[0].output;
  return null;
}

function slugify(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function titleCase(value) {
  return String(value || '')
    .toLowerCase()
    .replace(/\b\w/g, (match) => match.toUpperCase());
}

function parseUrls(value) {
  const matches = String(value || '').match(/https?:\/\/[^\s,]+/g);
  return Array.from(new Set(matches || []));
}

function formatCurrency(value) {
  const amount = Number(value);
  if (!Number.isFinite(amount) || amount <= 0) return null;
  return new Intl.NumberFormat('es-CO', {
    style: 'currency',
    currency: 'COP',
    maximumFractionDigits: 0,
  }).format(amount);
}

function numberFromText(value, pattern) {
  const match = String(value || '').match(pattern);
  if (!match) return null;
  const parsed = Number(match[1]);
  return Number.isFinite(parsed) ? parsed : null;
}

function uniqueLines(values = []) {
  const seen = new Set();
  const lines = [];
  for (const value of values) {
    const normalized = slugify(value);
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    lines.push(String(value).trim());
  }
  return lines;
}

function amenityLabel(rawValue) {
  const value = slugify(rawValue);
  const map = [
    { pattern: /piscina/, label: 'Piscina 🏊' },
    { pattern: /jacuzzi/, label: 'Jacuzzi 🛁' },
    { pattern: /kiosko|quiosco/, label: 'Kiosko 🔝' },
    { pattern: /tejo/, label: 'Cancha de tejo 🎯' },
    { pattern: /micro futbol|microfutbol|futbol/, label: 'Cancha de micro fútbol ⚽️' },
    { pattern: /ping pong/, label: 'Mesa de ping pong 🏓' },
    { pattern: /billar|pool|mini mesa de billar/, label: 'Mesa de billar 🎱' },
    { pattern: /rana/, label: 'Rana 🐸' },
    { pattern: /bbq/, label: 'BBQ ♨️' },
    { pattern: /zonas verdes|zona verde/, label: 'Zonas verdes 🌴' },
    { pattern: /wifi|wi fi/, label: 'Wifi 🛜' },
    { pattern: /golf/, label: 'Golf ⛳️' },
    { pattern: /tenis/, label: 'Tenis 🎾' },
    { pattern: /parqueadero/, label: 'Parqueadero 🚗' },
    { pattern: /pet friendly|mascotas/, label: 'Pet friendly 🐶' },
    { pattern: /empleada/, label: 'Servicio de empleada 👩‍🍳' },
  ];

  const matched = map.find((item) => item.pattern.test(value));
  if (matched) return matched.label;
  if (!value) return null;
  return titleCase(rawValue);
}

function buildHighlightLines(finca) {
  const combinedText = [
    finca.descripcion_corta,
    finca.observaciones_originales,
    finca.caracteristicas_originales,
    finca.especificacion_habitaciones,
  ]
    .filter(Boolean)
    .join('\n');

  const lines = [];

  if (finca.habitaciones) {
    lines.push(String(finca.habitaciones) + ' habitaciones 🍃');
  } else {
    const habitaciones = numberFromText(combinedText, /(\d+)\s+habitaciones?/i);
    if (habitaciones) lines.push(String(habitaciones) + ' habitaciones 🍃');
  }

  const banos = numberFromText(combinedText, /(\d+)\s+bañ?os?/i);
  if (banos) lines.push(String(banos) + ' baños 🚻');

  const amenidades = Array.isArray(finca.amenidades) ? finca.amenidades : [];
  for (const amenidad of amenidades) {
    const label = amenityLabel(amenidad);
    if (label) lines.push(label);
  }

  // capacidad_max no se muestra en la ficha (filtrada al matching, no se enseña al cliente)

  if (finca.municipio || finca.zona) {
    const locationLabel =
      finca.municipio && finca.zona && slugify(finca.municipio) !== slugify(finca.zona)
        ? 'Ubicada en ' + String(finca.municipio) + ', ' + String(finca.zona)
        : 'Ubicada en ' + String(finca.municipio || finca.zona);
    lines.push(locationLabel);
  }

  return uniqueLines(lines);
}

// ─── PRICING ENGINE v2 (date-aware, per category) ───
function getPricingSeasons() {
  try {
    var raw = $('Get agent settings').item.json.pricing_seasons;
    if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch (e) { raw = null; } }
    if (!raw || typeof raw !== 'object') return { festivos_y_puentes: [], semana_santa: [], temporada_alta: [] };
    return {
      festivos_y_puentes: Array.isArray(raw.festivos_y_puentes) ? raw.festivos_y_puentes : [],
      semana_santa: Array.isArray(raw.semana_santa) ? raw.semana_santa : [],
      temporada_alta: Array.isArray(raw.temporada_alta) ? raw.temporada_alta : [],
    };
  } catch (e) { return { festivos_y_puentes: [], semana_santa: [], temporada_alta: [] }; }
}
function _enumerateNights(startIso, endIso) {
  if (!startIso || !endIso) return [];
  var d1 = new Date(startIso); var d2 = new Date(endIso);
  if (isNaN(d1) || isNaN(d2)) return [];
  var nights = []; var cur = new Date(d1);
  while (cur < d2) { nights.push(cur.toISOString().slice(0,10)); cur.setUTCDate(cur.getUTCDate() + 1); }
  return nights;
}
function _dateInRange(iso, range) {
  if (!range || !range.from || !range.to) return false;
  return iso >= String(range.from) && iso <= String(range.to);
}
function _classifyNight(iso, seasons) {
  function findRange(list){ return (list||[]).find(function(r){ return _dateInRange(iso, r); }) || null; }
  var r;
  if ((r = findRange(seasons.temporada_alta)))    return { category: 'temporada_alta', range: r };
  if ((r = findRange(seasons.semana_santa)))      return { category: 'semana_santa', range: r };
  if ((r = findRange(seasons.festivos_y_puentes))) return { category: 'festivo', range: r };
  // Puente: si la noche cae en vie/sáb/dom Y el lunes siguiente es festivo,
  // esta noche también se cobra como festivo (puente).
  var d = new Date(iso + 'T00:00:00Z');
  var dow = d.getUTCDay(); // 0=Sun,1=Mon,...,5=Fri,6=Sat
  var daysToMonday = (dow === 5) ? 3 : (dow === 6) ? 2 : (dow === 0) ? 1 : -1;
  if (daysToMonday > 0) {
    var mon = new Date(d); mon.setUTCDate(d.getUTCDate() + daysToMonday);
    var monIso = mon.toISOString().slice(0,10);
    var puenteRange = findRange.call(null, seasons.festivos_y_puentes) ||
      (seasons.festivos_y_puentes || []).find(function(r){ return monIso >= String(r.from) && monIso <= String(r.to); });
    if (puenteRange) return { category: 'festivo', range: puenteRange };
  }
  return { category: 'standard', range: null };
}
// Default min_noches per category when range entry doesn't specify one
var _DEFAULT_CATEGORY_MIN_NOCHES = {
  festivo: 2,
  semana_santa: 3,
  temporada_alta: 3,
  standard: 1,
};
function _rangeMinNoches(category, range) {
  if (range && Number.isFinite(Number(range.min_noches))) return Number(range.min_noches);
  return _DEFAULT_CATEGORY_MIN_NOCHES[category] || 1;
}
function parseEmpleadaObligatoria(raw) {
  // Returns {count: number, per_personas: number|null, raw: string|null}.
  //   ""/null/0/"no"        -> {count:0, per_personas:null}    (not mandatory)
  //   "2" / 2               -> {count:2, per_personas:null}    (2 empleadas always)
  //   "1 por cada 8 personas" -> {count:0, per_personas:8}     (1 employee per 8 people)
  //   "1 cada 6"            -> {count:0, per_personas:6}
  if (raw === null || raw === undefined) return {count: 0, per_personas: null, raw: null};
  if (typeof raw === 'boolean') return {count: raw ? 1 : 0, per_personas: null, raw: String(raw)};
  if (typeof raw === 'number' && isFinite(raw)) return {count: Math.max(0, Math.floor(raw)), per_personas: null, raw: String(raw)};
  const s = String(raw).trim();
  if (!s) return {count: 0, per_personas: null, raw: null};
  const norm = s.toLowerCase()
    .replace(/[áä]/g,'a').replace(/[éë]/g,'e').replace(/[íï]/g,'i')
    .replace(/[óö]/g,'o').replace(/[úü]/g,'u');
  // Negative shortcuts
  if (/^(no|n|0|ninguna|ningun|sin|opcional|opcionales|no obligatori\w*)$/i.test(norm)) {
    return {count: 0, per_personas: null, raw: s};
  }
  // "X por cada Y (personas)?"
  let m = norm.match(/(\d+)\s*(?:empleadas?|emp\.?)?\s*(?:por\s+cada|cada|por|\/)\s*(\d+)\s*(?:personas?|huespedes?|pax)?/i);
  if (m) {
    const c = Number(m[1]);
    const ratio = Number(m[2]);
    if (isFinite(c) && c > 0 && isFinite(ratio) && ratio > 0) {
      return {count: 0, per_personas: Math.round(ratio / c), raw: s};
    }
  }
  // Plain number "2" or "2 empleadas"
  m = norm.match(/^\s*(\d+)\s*(?:empleadas?|emp\.?)?\s*$/);
  if (m) {
    const n = Number(m[1]);
    return {count: Math.max(0, Math.floor(n)), per_personas: null, raw: s};
  }
  // True-ish words → 1 (legacy boolean)
  if (/^(si|sí|s|true|y|yes|obligatori\w*)$/i.test(norm)) {
    return {count: 1, per_personas: null, raw: s};
  }
  // Fallback: extract any leading int
  m = norm.match(/(\d+)/);
  if (m) return {count: Math.max(0, parseInt(m[1],10)), per_personas: null, raw: s};
  return {count: 0, per_personas: null, raw: s};
}
function resolveEmpleadaCount(empObj, personas) {
  if (!empObj || typeof empObj !== 'object') return 0;
  if (empObj.count > 0) return empObj.count;
  if (empObj.per_personas && personas > 0) {
    return Math.max(1, Math.round(personas / empObj.per_personas));
  }
  return 0;
}

function computeQuote(finca, fechaInicio, fechaFin, personas) {
  if (!finca || typeof finca !== 'object') return null;
  if (!fechaInicio || !fechaFin) return null;
  var nights = _enumerateNights(fechaInicio, fechaFin);
  if (!nights.length) return null;
  var seasons = getPricingSeasons();
  var byCategory = { standard: 0, festivo: 0, semana_santa: 0, temporada_alta: 0 };
  // collect the matched ranges so we can compute effective_min_noches
  var matchedRanges = []; // { category, range, label, min_noches_required }
  nights.forEach(function(iso) {
    var cls = _classifyNight(iso, seasons);
    byCategory[cls.category]++;
    if (cls.category !== 'standard') {
      var minN = _rangeMinNoches(cls.category, cls.range);
      // dedupe by range label
      var label = cls.range && cls.range.label ? String(cls.range.label) : cls.category;
      if (!matchedRanges.find(function(m){ return m.label === label; })) {
        matchedRanges.push({ category: cls.category, label: label, range: cls.range, min_noches_required: minN });
      }
    }
  });
  // effective_min_noches = max(category requirements, finca.min_noches if any standard night)
  var fincaMin = Number.isFinite(Number(finca.min_noches)) ? Number(finca.min_noches) : 1;
  var effectiveMin = matchedRanges.reduce(function(m, r){ return Math.max(m, r.min_noches_required); }, 0);
  if (byCategory.standard > 0) effectiveMin = Math.max(effectiveMin, fincaMin);
  if (effectiveMin === 0) effectiveMin = fincaMin; // no special ranges, only finca rule
  var belowMinimum = nights.length < effectiveMin;
  var capMin = Number(finca.capacidad_minima || finca.capacidad_minima_tarifa || 0) || 0;
  var capMax = Number(finca.capacidad_max || 0) || 0;
  var personasN = Math.max(0, Number(personas) || 0);
  var extras = capMin > 0 ? Math.max(0, personasN - capMin) : 0;
  if (capMax > 0 && personasN > capMax) extras = Math.min(extras, Math.max(0, capMax - capMin));
  var lineItems = [];
  function pushLine(category, count, baseField, extraField, isFlat, label) {
    if (count <= 0) return;
    var base = Number(finca[baseField] || 0);
    if (!base) return;
    var extraRate = isFlat ? 0 : Number(finca[extraField] || 0);
    var perNight = base + extraRate * extras;
    lineItems.push({
      category: category, label: label, nights: count,
      base_per_night: base, extra_per_person: extraRate,
      extras_count: isFlat ? 0 : extras,
      per_night_total: perNight, subtotal: perNight * count,
    });
  }
  pushLine('standard',       byCategory.standard,       'precio_base_noche',           'precio_persona_extra_base',           false, 'Estándar');
  pushLine('festivo',        byCategory.festivo,        'precio_festivo',              'precio_persona_extra_festivo',        false, 'Festivo / puente');
  pushLine('semana_santa',   byCategory.semana_santa,   'precio_semana_santa_receso',  'precio_persona_extra_semana_santa',   true,  'Semana Santa');
  pushLine('temporada_alta', byCategory.temporada_alta, 'precio_temporada_alta',       'precio_persona_extra_temporada_alta', true,  'Temporada alta');
  var subtotal = lineItems.reduce(function(s,l){ return s + l.subtotal; }, 0);
  var deposito = Number(finca.deposito_seguridad || 0);
  var limpieza = Number(finca.limpieza_final_valor || 0);
  var empCount = resolveEmpleadaCount(finca.empleada_obligatorio, personasN);
  var empleadaPerDay = empCount > 0 ? Number(finca.servicio_empleada_valor_8h || 0) * empCount : 0;
  var empleada = empleadaPerDay * nights.length;
  var total = subtotal + deposito + limpieza + empleada;
  return {
    line_items: lineItems, total_nights: nights.length, personas: personasN,
    extras_aplicados_no_flat: extras, subtotal_noches: subtotal,
    deposito_seguridad: deposito, limpieza_final: limpieza,
    servicio_empleada_total: empleada, servicio_empleada_per_day: empleadaPerDay, servicio_empleada_count: empCount,
    total: total,
    effective_min_noches: effectiveMin,
    below_minimum: belowMinimum,
    matched_ranges: matchedRanges,
  };
}
// Helper used by Build Inventory Tool Response to filter fincas date-aware
function effectiveMinNochesFor(finca, fechaInicio, fechaFin) {
  var q = computeQuote(finca, fechaInicio, fechaFin, finca && finca.capacidad_minima ? finca.capacidad_minima : 1);
  return q && Number.isFinite(q.effective_min_noches) ? q.effective_min_noches : (Number(finca && finca.min_noches) || 1);
}
function _safeSearchCriteria() {
  try {
    var ctx = $('Get Context-conversations1').item.json || {};
    return ctx.search_criteria || (ctx.context && ctx.context.search_criteria) || {};
  } catch (e) { return {}; }
}

function buildTarifaLine(finca, quote) {
  function _isFlatCat(c) { return c === 'temporada_alta' || c === 'semana_santa'; }
  function _renderLine(li, capMin, personas, prefix) {
    var head = formatCurrency(li.base_per_night) + ' / noche';
    var isFlat = _isFlatCat(li.category);
    var personasStr = personas > 0 ? ' para ' + personas + ' persona' + (personas === 1 ? '' : 's') : '';
    if (isFlat) {
      // flat (temporada alta / semana santa): no per-person at quote time, always show personas count
      return prefix + head + personasStr;
    }
    // additive (standard / festivo)
    if (personas > capMin && li.extra_per_person > 0 && capMin > 0) {
      // group exceeds cap_min → show extra-person formula
      head += ' + ' + formatCurrency(li.extra_per_person) + ' por persona a partir de ' + capMin;
      return prefix + head;
    }
    // fits within cap_min → show plain rate + personas (so customer knows boundary)
    return prefix + head + personasStr;
  }
  if (quote && Array.isArray(quote.line_items) && quote.line_items.length && quote.total_nights > 0) {
    var capMin = Number(finca.capacidad_minima) || 0;
    var personasN = Number(quote.personas) || 0;
    if (quote.line_items.length === 1) {
      return _renderLine(quote.line_items[0], capMin, personasN, '💰 ');
    }
    // mixed temporadas → breakdown
    var lines = ['💰 *Cotización para esas fechas:*'];
    quote.line_items.forEach(function (li) {
      var nightsLabel = li.nights + ' noche' + (li.nights === 1 ? '' : 's');
      lines.push('   • ' + nightsLabel + ' ' + li.label + ': ' + _renderLine(li, capMin, personasN, ''));
    });
    return lines.join('\n');
  }
  // Fallback (no fechas): muestra base estándar + extras desde cap_min si aplica
  var capMin = Number(finca.capacidad_minima) || 0;
  var base = Number(finca.precio_base_noche || finca.precio_noche_base || 0);
  var xtra = Number(finca.precio_persona_extra_base || finca.precio_persona_extra || 0);
  if (base > 0) {
    var head = '💰 desde ' + formatCurrency(base) + ' / noche';
    if (xtra > 0 && capMin > 0) {
      head += ' + ' + formatCurrency(xtra) + ' por persona a partir de ' + capMin;
    }
    return head;
  }
  if (finca.precio_festivo || finca.precio_fin_semana || finca.precio_referencia_noche) {
    return '💰 desde ' + formatCurrency(finca.precio_festivo || finca.precio_fin_semana || finca.precio_referencia_noche) + ' / noche';
  }
  return null;
}

function buildFincaCard(finca) {
  if (!finca || typeof finca !== 'object') return null;
  const title = String(finca.codigo_original || finca.finca_id || 'Finca').trim();
  const code = String(finca.codigo_original || finca.finca_id || '').trim();
  const highlights = buildHighlightLines(finca);
  const sc = _safeSearchCriteria();
  const quote = computeQuote(finca, sc.fecha_inicio, sc.fecha_fin, sc.personas);
  const tarifa = buildTarifaLine(finca, quote);
  const tipos = (Array.isArray(finca.tipo_evento) ? finca.tipo_evento : []).map(function(t){ return String(t).toLowerCase(); });
  const aceptaEventos = tipos.some(function(t){ return t.indexOf('evento')>=0 || t.indexOf('fiesta')>=0; });
  const aceptaFamiliar = tipos.some(function(t){ return t.indexOf('familiar')>=0 || t.indexOf('vacacion')>=0; });
  const indicadoresExtra = [];
  if (finca.pet_friendly === true) indicadoresExtra.push('🐕 Acepta mascotas');
  if (aceptaEventos) indicadoresExtra.push('🎉 Apto para eventos / fiestas');
  else if (aceptaFamiliar) indicadoresExtra.push('👨‍👩‍👧 Vacacional / familiar');
  const parts = [
    '☀️🌴*' + title + '*🌴☀️',
    code && code !== title ? code : null,
    null,
    ...highlights.map((line) => '- ' + line),
    finca.tiempo_en_vehiculo ? '🚗 ' + String(finca.tiempo_en_vehiculo) + ' al pueblo' : null,
    finca.acomodacion_por_habitacion
      ? 'Acomodación por habitación: ' + String(finca.acomodacion_por_habitacion)
      : finca.especificacion_habitaciones
        ? 'Acomodación: ' + String(finca.especificacion_habitaciones)
        : null,
    finca.servicios_adicionales_texto
      ? 'Servicios adicionales: ' + String(finca.servicios_adicionales_texto)
      : null,
    (function() {
      var emp = finca.empleada_obligatorio;
      var sc2 = _safeSearchCriteria();
      var pp = Number(sc2.personas) || 0;
      var c = resolveEmpleadaCount(emp, pp);
      if (c <= 0) return null;
      var per8 = Number(finca.servicio_empleada_valor_8h || 0);
      if (per8 <= 0) return null;
      var perDay = per8 * c;
      var nightsCount = (quote && quote.total_nights) ? quote.total_nights : 0;
      var head = '👩\u200d🍳 Servicio empleada obligatorio: ' + formatCurrency(perDay) + '/día';
      if (c > 1) head += ' (' + c + ' empleadas)';
      if (nightsCount > 0) head += ' · total ' + formatCurrency(perDay * nightsCount) + ' por ' + nightsCount + ' noche' + (nightsCount===1?'':'s');
      return head;
    })(),
    indicadoresExtra.length ? indicadoresExtra.join('  •  ') : null,
    null,
    tarifa,
  ].filter((value) => value !== null && value !== undefined && String(value).trim() !== '');
  return parts.join('\n');
}

function buildMediaMessages(finca) {
  const urls = parseUrls(finca?.foto_url);
  if (!urls.length) return [];
  const title = finca?.codigo_original || finca?.finca_id || 'la finca';
  return [
    {
      type: 'media_group',
      content: '',
      media_url: urls[0],
      media_urls: urls,
      property_title: title,
      property_id: finca?.finca_id || null,
      media_count: urls.length,
    },
  ];
}

function createTextMessage(content, extra = {}) {
  const text = String(content || '').trim();
  if (!text) return null;
  return {
    type: extra.type || 'text',
    content: text,
    media_url: extra.media_url || null,
    media_urls: Array.isArray(extra.media_urls) ? extra.media_urls : undefined,
    property_title: extra.property_title || null,
    property_id: extra.property_id || null,
  };
}

function daysBetweenIsoDates(start, end) {
  if (!start || !end) return null;
  const d1 = new Date(start); const d2 = new Date(end);
  if (isNaN(d1) || isNaN(d2)) return null;
  return Math.max(0, Math.round((d2 - d1) / 86400000));
}

function encodeBase64UrlJson(obj) {
  const json = JSON.stringify(obj);
  const buf = Buffer.from(json, 'utf8');
  return buf.toString('base64').replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

function textToPaymentMethods(text) {
  if (!text) return [];
  return String(text).split('\n').map(function(line) {
    var trimmed = line.trim();
    if (!trimmed) return null;
    var match = trimmed.match(/^(.+?)\s*[\-–—:]\s*(.+)$/);
    if (match) return { method: match[1].trim(), description: match[2].trim() };
    return { method: trimmed, description: '' };
  }).filter(Boolean);
}

function createReservationDocumentItem(selectedFinca, toolOutputParsed, finalWhatsappText) {
  if (!toolOutputParsed || toolOutputParsed.intent !== 'DOCUMENT_READY') return null;
  var publicBase = String($('config').item.json.public_app_base_url || '').trim();
  if (!publicBase) return null;

  var finca = selectedFinca || {};
  var criteria = $('Get Context-conversations1').item.json.search_criteria || $('Get Context-conversations1').item.json.context?.search_criteria || {};
  var confirmData = toolOutputParsed.confirmation_data_update || {};
  var extras = $('Get Context-conversations1').item.json.extras || {};
  var prevConfirm = extras.confirming_reservation || {};
  var merged = Object.assign({}, prevConfirm, confirmData);

  var noches = daysBetweenIsoDates(criteria.fecha_inicio, criteria.fecha_fin);
  var quote = computeQuote(finca, criteria.fecha_inicio, criteria.fecha_fin, criteria.personas);
  var tarifaNoche, limpieza, subtotal, total, deposito;
  var empleadaPerDay = 0, empleadaTotal = 0, empleadaCount = 0;
  if (quote && quote.line_items.length) {
    tarifaNoche   = quote.total_nights ? Math.round(quote.subtotal_noches / quote.total_nights) : 0;
    subtotal      = quote.subtotal_noches;
    limpieza      = quote.limpieza_final;
    deposito      = quote.deposito_seguridad;
    empleadaPerDay= Number(quote.servicio_empleada_per_day || 0);
    empleadaTotal = Number(quote.servicio_empleada_total || 0);
    empleadaCount = Number(quote.servicio_empleada_count || 0);
    total         = quote.total;
  } else {
    tarifaNoche = Number(finca.precio_base_noche || finca.precio_noche_base || finca.precio_fin_semana || finca.precio_referencia_noche || 0);
    limpieza    = Number(finca.limpieza_final_valor || 0);
    deposito    = Number(finca.deposito_seguridad || 0);
    // Empleada fallback: compute manually from finca data if quote unavailable.
    var empObj  = finca.empleada_obligatorio || {};
    empleadaCount = (empObj.count > 0) ? empObj.count : ((empObj.per_personas && criteria.personas) ? Math.max(1, Math.round(Number(criteria.personas)/empObj.per_personas)) : 0);
    empleadaPerDay = empleadaCount > 0 ? Number(finca.servicio_empleada_valor_8h || 0) * empleadaCount : 0;
    empleadaTotal  = empleadaPerDay * (noches || 0);
    subtotal    = noches && tarifaNoche ? noches * tarifaNoche : 0;
    total       = subtotal + limpieza + deposito + empleadaTotal;
  }

  var payload = {
    property_code: finca.codigo_original || finca.finca_id || '',
    property_name: finca.nombre || '',
    property_zone: finca.zona || '',
    property_municipio: finca.municipio || '',
    fecha_inicio: criteria.fecha_inicio || '',
    fecha_fin: criteria.fecha_fin || '',
    noches: noches,
    check_in: '15:00h',
    check_out: '11:00h',
    tarifa_noche: tarifaNoche,
    limpieza_final: limpieza,
    deposito: deposito,
    servicio_empleada_per_day: empleadaPerDay,
    servicio_empleada_total: empleadaTotal,
    servicio_empleada_count: empleadaCount,
    quote_breakdown: quote && quote.line_items ? quote.line_items : [],
    huespedes: criteria.personas || '',
    subtotal: subtotal,
    total: total,
    anticipo_requerido: Math.round(total * 0.5),
    client_name: merged.nombre_completo || '',
    client_document_type: merged.tipo_documento || '',
    client_document_number: merged.numero_documento || '',
    client_phone: merged.celular || $('Merge Sets1').item.json.conversation_key || '',
    client_email: merged.correo || '',
    client_address: merged.direccion || '',
    tiempo_en_vehiculo: finca.tiempo_en_vehiculo || '',
    acomodacion_por_habitacion: finca.acomodacion_por_habitacion || '',
    servicios_adicionales_texto: finca.servicios_adicionales_texto || '',
    payment_methods_text: $('config').item.json.payment_methods_text || '',
    company_knowledge: $('config').item.json.company_knowledge || '',
  };

  var encoded = encodeBase64UrlJson(payload);
  var pdfUrl = publicBase.replace(/\/$/, '') + '/api/reservation-confirmation.docx?payload=' + encoded;

  var label = 'Confirmacion de reserva' + (payload.property_code ? ' - ' + payload.property_code : '');

  return {
    type: 'media_group',
    content: finalWhatsappText || label,
    media_url: pdfUrl,
    media_urls: [pdfUrl],
    property_title: null,
    property_id: finca.finca_id || null,
    media_count: 1,
  };
}

function normalizeDocumentsToSend(raw) {
  if (!Array.isArray(raw)) return [];
  return raw.filter(function(doc) { return doc && typeof doc === 'object' && doc.url; });
}

function createCompanyDocumentItems(docs, trailingText) {
  var items = [];
  var text = createTextMessage(trailingText);
  if (text) items.push(text);
  for (var i = 0; i < docs.length; i++) {
    var doc = docs[i];
    items.push({
      type: 'media_group',
      content: doc.title || doc.document_key || 'Documento',
      media_url: doc.url,
      media_urls: [doc.url],
