// === pricing seasons (date-aware min_noches) ===
function _seasonsBIRP() {
  try {
    var raw = $('Get agent settings').item.json.pricing_seasons;
    if (typeof raw === 'string') { try { raw = JSON.parse(raw); } catch (e) { raw = null; } }
    if (!raw || typeof raw !== 'object') return { festivos_y_puentes: [], semana_santa: [], temporada_alta: [] };
    return {
      festivos_y_puentes: Array.isArray(raw.festivos_y_puentes) ? raw.festivos_y_puentes : [],
      semana_santa: Array.isArray(raw.semana_santa) ? raw.semana_santa : [],
      temporada_alta: Array.isArray(raw.temporada_alta) ? raw.temporada_alta : [],
    };
  } catch (e) { return { festivos_y_puentes: [], semana_santa: [], temporada_alta: [] }; }
}
function _enumerateNightsBIRP(s, e) {
  if (!s || !e) return [];
  var d1 = new Date(s); var d2 = new Date(e);
  if (isNaN(d1) || isNaN(d2)) return [];
  var out = []; var cur = new Date(d1);
  while (cur < d2) { out.push(cur.toISOString().slice(0,10)); cur.setUTCDate(cur.getUTCDate()+1); }
  return out;
}
function _classifyNightBIRP(iso, seasons) {
  function find(list){ return (list||[]).find(function(r){ return r && r.from && r.to && iso >= String(r.from) && iso <= String(r.to); }) || null; }
  function findIso(list, ts){ return (list||[]).find(function(r){ return r && r.from && r.to && ts >= String(r.from) && ts <= String(r.to); }) || null; }
  var r;
  if ((r = find(seasons.temporada_alta)))    return { category: 'temporada_alta', range: r };
  if ((r = find(seasons.semana_santa)))      return { category: 'semana_santa', range: r };
  if ((r = find(seasons.festivos_y_puentes))) return { category: 'festivo', range: r };
  // Puente: vie/sáb/dom → si el lunes siguiente es festivo, esta noche es festivo.
  var d = new Date(iso + 'T00:00:00Z');
  var dow = d.getUTCDay();
  var daysToMonday = (dow === 5) ? 3 : (dow === 6) ? 2 : (dow === 0) ? 1 : -1;
  if (daysToMonday > 0) {
    var mon = new Date(d); mon.setUTCDate(d.getUTCDate() + daysToMonday);
    var monIso = mon.toISOString().slice(0,10);
    var puente = findIso(seasons.festivos_y_puentes, monIso);
    if (puente) return { category: 'festivo', range: puente };
  }
  return { category: 'standard', range: null };
}
var _DEFAULT_CAT_MIN_BIRP = { festivo: 2, semana_santa: 3, temporada_alta: 3, standard: 1 };
// fechas_no_disponibles overlap check
function _bookingOverlapsUnavailable(item, fechaInicio, fechaFin) {
  if (!fechaInicio || !fechaFin) return false;
  const ranges = Array.isArray(item.fechas_no_disponibles) ? item.fechas_no_disponibles : [];
  if (!ranges.length) return false;
  const start = String(fechaInicio).slice(0,10);
  const end = String(fechaFin).slice(0,10);
  // booking is [start, end). a "blocked" range is [from, to] inclusive.
  // overlap iff start <= range.to AND end > range.from
  for (const r of ranges) {
    const rf = String(r.from || '').slice(0,10);
    const rt = String(r.to || '').slice(0,10);
    if (!rf || !rt) continue;
    if (start <= rt && end > rf) return true;
  }
  return false;
}

function _effectiveMinNochesBIRP(item, fechaInicio, fechaFin) {
  var ngs = _enumerateNightsBIRP(fechaInicio, fechaFin);
  if (!ngs.length) return Number(item && item.min_noches) || 1;
  var seasons = _seasonsBIRP();
  var maxReq = 0; var hasStandard = false;
  ngs.forEach(function(iso){
    var cls = _classifyNightBIRP(iso, seasons);
    if (cls.category === 'standard') { hasStandard = true; return; }
    var req = (cls.range && Number.isFinite(Number(cls.range.min_noches))) ? Number(cls.range.min_noches) : (_DEFAULT_CAT_MIN_BIRP[cls.category] || 1);
    if (req > maxReq) maxReq = req;
  });
  if (hasStandard) maxReq = Math.max(maxReq, Number(item && item.min_noches) || 1);
  if (maxReq === 0) maxReq = Number(item && item.min_noches) || 1;
  return maxReq;
}

const TOKEN_STOPWORDS = new Set([
  'al','de','del','en','la','las','el','los','un','una','unos','unas','y','o','pero','para','por','que','si','no','con','sin','su','sus','este','esta','estos','estas','ese','esa','eso','mi','tu','me','te','se','le','les','lo','ya','mas','muy','sea','son',
  'fincas','finca','propiedad','propiedades','casa','cabana','cabanas',
