const calculateNights = (start, end) => {
  if (!start || !end) return null;
  const startDate = new Date(start);
  const endDate = new Date(end);
  if (Number.isNaN(startDate.getTime()) || Number.isNaN(endDate.getTime())) return null;
  const diff = Math.round((endDate.getTime() - startDate.getTime()) / 86400000);
  return diff > 0 ? diff : null;
};

const nightlyReference = (item, nights) => {
  if (item.precio_noche_base) return item.precio_noche_base;
  if (item.precio_fin_semana && nights) return Math.round(item.precio_fin_semana / Math.max(nights, 2));
  if (item.precio_fin_semana) return Math.round(item.precio_fin_semana / 2);
  return null;
};

// === [Quote] Deterministic price computation for the LLM ===
// El motor de pricing tambien vive en CodeJS1.computeQuote — esta copia
// es necesaria porque el LLM responde preguntas de precio usando el
// payload de este tool. Si las dos copias divergen, las cards y las
// respuestas del LLM van a dar precios distintos. Mantener en SYNC.
function _resolveEmpleadaCountBIRP(empObj, personas) {
  if (!empObj || typeof empObj !== 'object') return 0;
  if (empObj.count > 0) return empObj.count;
  if (empObj.per_personas && personas > 0) {
    return Math.max(1, Math.round(personas / empObj.per_personas));
  }
  return 0;
}
function _fmtCOP(value) {
  var n = Number(value);
  if (!Number.isFinite(n) || n <= 0) return '';
  try {
    return new Intl.NumberFormat('es-CO', { style: 'currency', currency: 'COP', maximumFractionDigits: 0 }).format(n);
  } catch (e) {
    return '$' + Math.round(n).toLocaleString('es-CO');
  }
}
function _computeQuoteBIRP(finca, fechaInicio, fechaFin, personas) {
  if (!finca || typeof finca !== 'object') return null;
  if (!fechaInicio || !fechaFin) return null;
  var nights = _enumerateNightsBIRP(fechaInicio, fechaFin);
  if (!nights.length) return null;
  var seasons = _seasonsBIRP();
  var byCategory = { standard: 0, festivo: 0, semana_santa: 0, temporada_alta: 0 };
  var matchedRanges = [];
  nights.forEach(function(iso) {
    var cls = _classifyNightBIRP(iso, seasons);
    byCategory[cls.category]++;
    if (cls.category !== 'standard') {
      var minN = (cls.range && Number.isFinite(Number(cls.range.min_noches))) ? Number(cls.range.min_noches) : (_DEFAULT_CAT_MIN_BIRP[cls.category] || 1);
      var label = cls.range && cls.range.label ? String(cls.range.label) : cls.category;
      if (!matchedRanges.find(function(m){ return m.label === label; })) {
        matchedRanges.push({ category: cls.category, label: label, min_noches_required: minN });
      }
    }
  });
  var fincaMin = Number.isFinite(Number(finca.min_noches)) ? Number(finca.min_noches) : 1;
  var effectiveMin = matchedRanges.reduce(function(m, r){ return Math.max(m, r.min_noches_required); }, 0);
  if (byCategory.standard > 0) effectiveMin = Math.max(effectiveMin, fincaMin);
  if (effectiveMin === 0) effectiveMin = fincaMin;
  var belowMinimum = nights.length < effectiveMin;
  var capMin = Number(finca.capacidad_minima || finca.capacidad_minima_tarifa || 0) || 0;
  var capMax = Number(finca.capacidad_max || 0) || 0;
  var personasN = Math.max(0, Number(personas) || 0);
  var extras = capMin > 0 ? Math.max(0, personasN - capMin) : 0;
  if (capMax > 0 && personasN > capMax) extras = Math.min(extras, Math.max(0, capMax - capMin));
  var lineItems = [];
  function pushLine(category, count, baseField, extraField, isFlat, label) {
    if (count <= 0) return;
    var base = Number(finca[baseField] || 0);
    if (!base) return;
    var extraRate = isFlat ? 0 : Number(finca[extraField] || 0);
    var perNight = base + extraRate * extras;
    lineItems.push({
      category: category, label: label, nights: count,
      base_per_night: base, extra_per_person: extraRate,
      extras_count: isFlat ? 0 : extras,
      per_night_total: perNight, subtotal: perNight * count,
      is_flat: !!isFlat,
    });
  }
  pushLine('standard',       byCategory.standard,       'precio_base_noche',           'precio_persona_extra_base',           false, 'Estándar');
  pushLine('festivo',        byCategory.festivo,        'precio_festivo',              'precio_persona_extra_festivo',        false, 'Festivo / puente');
  pushLine('semana_santa',   byCategory.semana_santa,   'precio_semana_santa_receso',  'precio_persona_extra_semana_santa',   true,  'Semana Santa');
  pushLine('temporada_alta', byCategory.temporada_alta, 'precio_temporada_alta',       'precio_persona_extra_temporada_alta', true,  'Temporada alta');
  var subtotal = lineItems.reduce(function(s,l){ return s + l.subtotal; }, 0);
  var deposito = Number(finca.deposito_seguridad || 0);
  var limpieza = Number(finca.limpieza_final_valor || 0);
  var empCount = _resolveEmpleadaCountBIRP(finca.empleada_obligatorio, personasN);
  var empleadaPerDay = empCount > 0 ? Number(finca.servicio_empleada_valor_8h || 0) * empCount : 0;
  var empleada = empleadaPerDay * nights.length;
  var total = subtotal + deposito + limpieza + empleada;
  // human_summary — texto listo para copiar/pegar por el LLM
  var summaryParts = [];
  if (lineItems.length === 1) {
    var li = lineItems[0];
    var cat = li.category === 'standard' ? 'estándar' : (li.label || li.category).toLowerCase();
    summaryParts.push(_fmtCOP(li.per_night_total) + '/noche · ' + nights.length + ' noche' + (nights.length===1?'':'s') + (li.category === 'standard' ? '' : ' en ' + cat));
  } else if (lineItems.length > 1) {
    summaryParts.push(lineItems.map(function(li){
      return li.nights + ' ' + (li.nights===1?'noche':'noches') + ' a ' + _fmtCOP(li.per_night_total) + (li.category==='standard'?'':' (' + (li.label||li.category).toLowerCase() + ')');
    }).join(' + '));
  }
  if (lineItems.length) summaryParts.push('subtotal noches ' + _fmtCOP(subtotal));
  if (deposito > 0) summaryParts.push('depósito ' + _fmtCOP(deposito));
  if (limpieza > 0) summaryParts.push('limpieza ' + _fmtCOP(limpieza));
  if (empleada > 0) summaryParts.push('servicio empleada ' + _fmtCOP(empleada) + (empCount > 1 ? ' (' + empCount + ' empleadas)' : ''));
  summaryParts.push('TOTAL ' + _fmtCOP(total));
  var humanSummary = summaryParts.join(' · ');
  return {
    line_items: lineItems,
    total_nights: nights.length,
    personas: personasN,
    extras_aplicados_no_flat: extras,
    subtotal_noches: subtotal,
    deposito_seguridad: deposito,
    limpieza_final: limpieza,
    servicio_empleada_total: empleada,
    servicio_empleada_per_day: empleadaPerDay,
    servicio_empleada_count: empCount,
    total: total,
    effective_min_noches: effectiveMin,
    below_minimum: belowMinimum,
    matched_ranges: matchedRanges,
    human_summary: humanSummary,
    fecha_inicio: String(fechaInicio).slice(0,10),
    fecha_fin: String(fechaFin).slice(0,10),
  };
}

