    },
  ];
}

return [
  {
    json: {
      error: false,
      operation: 'get_finca_details',
      matched_count: bestMatch ? 1 : 0,
      items: [],
      similar_items: [],
      selected_finca: bestMatch ? sanitizeDetailItem(bestMatch, nights) : null,
      owner: null,
      search_applied: {
        finca_id: explicitFincaId || null,
        nombre: explicitName || null,
        query,
      },
      notes: bestMatch ? null : 'finca_not_found',
    },
  },
];

const payload = $json.body && typeof $json.body === 'object' ? $json.body : ($json || {});
// === reply context: WhatsApp/Chatwoot puts the replied-to message id here ===
const __ca = (payload.content_attributes && typeof payload.content_attributes === 'object') ? payload.content_attributes : {};
const repliedToChatwootMessageId =
  Number(__ca.in_reply_to) ||
  Number(payload.in_reply_to) ||
  Number(payload.reply_to) ||
  null;
const digitsOnly = (value) => String(value || '').replace(/\D+/g, '').trim();
const compact = (value) => String(value || '').trim();
const toNullableBoolean = (value) => {
  if (value === true || value === false) return value;
  if (value === null || value === undefined || value === '') return null;
  const normalized = String(value).trim().toLowerCase();
  if (['true', '1', 'yes', 'si', 'sí', 'on'].includes(normalized)) return true;
  if (['false', '0', 'no', 'off'].includes(normalized)) return false;
  return null;
};
const ensureArray = (value) => {
  if (Array.isArray(value)) return value;
  if (value && typeof value === 'object') return [value];
  return [];
};
const firstNonEmpty = (...values) => values.map(compact).find(Boolean) || null;
const audioPattern = /\.(aac|m4a|mp3|ogg|oga|opus|wav|webm)(\?|$)/i;

const attachmentUrl = (attachment) =>
  firstNonEmpty(
    attachment?.data_url,
    attachment?.download_url,
    attachment?.file_url,
    attachment?.external_url,
    attachment?.url,
    attachment?.proxy_url,
    attachment?.blob_url,
    attachment?.content_url,
    attachment?.file?.url,
  );
const attachmentMimeType = (attachment) =>
  firstNonEmpty(
    attachment?.mime_type,
    attachment?.content_type,
    attachment?.file_type,
    attachment?.data_type,
    attachment?.file?.content_type,
    attachment?.file?.mime_type,
  );
const attachmentFilename = (attachment) =>
  firstNonEmpty(
    attachment?.filename,
    attachment?.file_name,
    attachment?.name,
    attachment?.file?.filename,
    attachment?.file?.name,
  );
const attachmentLooksAudio = (attachment) => {
  const mimeType = String(attachmentMimeType(attachment) || '').toLowerCase();
  const filename = String(attachmentFilename(attachment) || '').toLowerCase();
  const url = String(attachmentUrl(attachment) || '').toLowerCase();
  const type = String(
    attachment?.type ||
      attachment?.attachment_type ||
      attachment?.resource_type ||
      attachment?.file?.resource_type ||
      '',
  ).toLowerCase();
  return (
    mimeType.startsWith('audio/') ||
    type === 'audio' ||
    audioPattern.test(filename) ||
    audioPattern.test(url)
  );
};

const looksLikeChatwoot =
  payload.event !== undefined ||
  payload.conversation !== undefined ||
  payload.contact !== undefined ||
  payload.sender !== undefined;

