  const waId = digitsOnly(payload.wa_id || payload.phone || payload.conversationId || payload.sessionId);
  const chatInput = compact(payload.chatInput || payload.text || payload.current_message);
  const internalResume = toNullableBoolean(payload.internal_resume) === true;
  return [
    {
      json: {
        source: 'simulator',
        replied_to_chatwoot_message_id: repliedToChatwootMessageId,
        event_type: 'message_created',
        is_sync_event: false,
        eligible: Boolean(waId && (chatInput || internalResume)),
        ignore_reason: waId && (chatInput || internalResume) ? null : 'missing_wa_id_or_text',
        chatInput,
        current_message: compact(payload.current_message || ''),
        chatwoot_id: payload.chatwoot_id || null,
        chatwoot_status: null,
        chatwoot_message_id: payload.chatwoot_message_id || null,
        wa_message_id: payload.wa_message_id || null,
        inbox_id: payload.inbox_id || null,
        inbox_name: payload.inbox_name || null,
        contact_source_id: payload.contact_source_id || null,
        insertar_mensjae:
          typeof payload.insertar_mensjae === 'boolean'
            ? payload.insertar_mensjae
            : toNullableBoolean(payload.insertar_mensjae),
        skip_validator: payload.skip_validator === true,
        forced_state: compact(payload.forced_state || '') || null,
        loop_reason: compact(payload.loop_reason || '') || null,
        owner_unavailable: payload.owner_unavailable === true,
        internal_resume: internalResume,
        wa_id: waId,
        client_name: compact(payload.client_name || payload.clientName || waId) || null,
        message_type: 'TEXT',
        original_message_type: 'TEXT',
        audio_url: null,
        audio_mime_type: null,
        audio_filename: null,
        audio_transcript: null,
        audio_metadata: null,
        audio_transcription_failed: false,
        audio_error_message: null,
        ia_activa: null,
        ia_activa_present: false,
        local_sequence: Number(payload.local_sequence || 0) || 0,
        client_message_id: compact(payload.client_message_id || payload.clientMessageId) || null,
      },
    },
  ];
}

const eventType = String(payload.event || '').toLowerCase();
const conversationId = payload.conversation?.id || payload.conversation_id || null;
const conversationStatus =
  payload.conversation?.status ||
  payload.conversation_status ||
  payload.status ||
  null;
const phoneCandidates = [
  payload.contact?.phone_number,
  payload.sender?.phone_number,
  payload.conversation?.meta?.sender?.phone_number,
  payload.meta?.sender?.phone_number,
  payload.contact_inbox?.source_id,
  payload.conversation?.meta?.contact?.phone_number,
];
const waId = phoneCandidates.map(digitsOnly).find(Boolean) || '';
const senderType = String(
  payload.sender?.type ||
    payload.sender_type ||
    payload.conversation?.meta?.sender?.type ||
    '',
).toLowerCase();
const messageDirection = String(payload.message_type || '').toLowerCase();
const privateMessage = payload.private === true;
const content =
  compact(payload.content) ||
  compact(payload.message?.content) ||
  compact(payload.message_content);
const syncEvent = eventType === 'conversation_created' || eventType === 'conversation_updated';
const incoming =
  messageDirection === 'incoming' ||
  messageDirection === '0' ||
  senderType === 'contact' ||
  payload.incoming === true;
const customIaRaw =
  payload.conversation?.custom_attributes?.ia_activa ??
  payload.custom_attributes?.ia_activa ??
  payload.changed_attributes?.custom_attributes?.ia_activa ??
  payload.changed_attributes?.ia_activa ??
  null;
const iaActiva = toNullableBoolean(customIaRaw);
const iaActivaPresent = !(customIaRaw === null || customIaRaw === undefined || customIaRaw === '');

const rawAttachments = [
  ...ensureArray(payload.attachments),
  ...ensureArray(payload.message?.attachments),
  ...ensureArray(payload.content_attributes?.attachments),
  ...ensureArray(payload.message?.content_attributes?.attachments),
  ...ensureArray(payload.attachment),
  ...ensureArray(payload.message?.attachment),
];
const audioAttachment = rawAttachments.find(attachmentLooksAudio) || null;
const normalizedMessageType = audioAttachment ? 'AUDIO' : 'TEXT';
const chatwootMessageId = payload.id || payload.message?.id || payload.message_id || null;

let ignoreReason = null;

if (syncEvent) {
  if (!waId && !conversationId) {
    ignoreReason = 'missing_conversation_identity';
  }
} else if (eventType && eventType !== 'message_created') {
  ignoreReason = 'unsupported_event';
} else if (privateMessage) {
  ignoreReason = 'private_message';
} else if (!incoming) {
  ignoreReason = 'not_incoming_customer_message';
} else if (!content && !audioAttachment) {
  ignoreReason = 'empty_content';
} else if (!waId && !conversationId) {
  ignoreReason = 'missing_phone_number_and_chatwoot_thread';
}

return [
  {
    json: {
      source: 'chatwoot',
      event_type: eventType || 'message_created',
      is_sync_event: syncEvent,
      eligible: ignoreReason === null,
      ignore_reason: ignoreReason,
      chatInput: content,
      chatwoot_id: conversationId ? String(conversationId) : null,
