    ? rawPayload.data
    : typeof rawPayload.body === 'string'
      ? rawPayload.body
      : typeof rawPayload.output === 'string'
        ? rawPayload.output
        : typeof rawPayload.raw === 'string'
          ? rawPayload.raw
          : '';

if (rawPayload.error || rawPayload.errorMessage || rawPayload.message) {
  return buildError(rawPayload.errorMessage || rawPayload.message || 'inventory_http_error');
}

if (!compact(csvText)) {
  return buildError('inventory_empty_response');
}

const parseCsv = (text) => {
  const rows = [];
  let row = [];
  let cell = '';
  let index = 0;
  let inQuotes = false;
  const source = String(text || '').replace(/^\uFEFF/, '');

  while (index < source.length) {
    const char = source[index];

    if (inQuotes) {
      if (char === '"') {
        if (source[index + 1] === '"') {
          cell += '"';
          index += 2;
          continue;
        }
        inQuotes = false;
        index += 1;
        continue;
      }

      cell += char;
      index += 1;
      continue;
    }

    if (char === '"') {
      inQuotes = true;
      index += 1;
      continue;
    }

    if (char === ',') {
      row.push(cell);
      cell = '';
      index += 1;
      continue;
    }

    if (char === '\r') {
      index += 1;
      continue;
    }

    if (char === '\n') {
      row.push(cell);
      rows.push(row);
      row = [];
      cell = '';
      index += 1;
      continue;
    }

    cell += char;
    index += 1;
  }

  row.push(cell);
  if (row.length > 1 || compact(row[0])) {
    rows.push(row);
  }

  return rows;
};

const matrixToObjects = (matrix) => {
  if (!Array.isArray(matrix) || matrix.length === 0) return [];
  const headers = matrix[0].map((header) => compact(header));

  return matrix
    .slice(1)
    .filter((values) => values.some((value) => compact(value)))
    .map((values) => {
      const rowObject = {};
      headers.forEach((header, idx) => {
        if (!header) return;
        rowObject[header] = values[idx] ?? '';
      });
      return rowObject;
    });
};

let matrix;
try {
  matrix = parseCsv(csvText);
} catch (error) {
  return buildError('inventory_csv_parse_error', { details: String(error?.message || error) });
}

const rows = matrixToObjects(matrix);

if (!rows.length) {
  return [{ json: {} }];
}

return rows.map((row) => ({ json: row }));

