try {
  const pgRow = $('Resolve replied finca').first().json;
  if (pgRow && pgRow.finca_id) { finca = String(pgRow.finca_id); kind = String(pgRow.message_kind || ''); }
} catch (e) {}

// Chatwoot snippet — find the original message by id in the list returned by HTTP
let originalSnippet = null;
let originalMessageType = null;
let originalAttachmentTypes = null;
try {
  const cwResp = $('Fetch chatwoot messages for reply').first().json;
  const list = (cwResp && (cwResp.payload || cwResp.data?.payload || cwResp.data || [])) || [];
  if (Array.isArray(list) && repliedId) {
    const found = list.find((m) => String(m && m.id) === String(repliedId));
    if (found) {
      originalSnippet = String(found.content || '').slice(0, 280);
      originalMessageType = found.message_type === 1 || found.message_type === 'outgoing' ? 'bot' : 'user';
      const att = Array.isArray(found.attachments) ? found.attachments : [];
      if (att.length) originalAttachmentTypes = att.map((a) => a.file_type).filter(Boolean);
    }
  }
} catch (e) {}

return [
  {
    json: {
      ...orig,
      replied_to_finca_id: finca,
      replied_to_message_kind: kind,
      replied_to_original_text: originalSnippet,
      replied_to_original_sender: originalMessageType,
      replied_to_original_attachments: originalAttachmentTypes,
    },
  },
];

// OpenAI Whisper multipart needs a filename for the `file` part. The
// Chatwoot attachment download lacks Content-Disposition, so binary.data
// arrives with fileName=null and OpenAI refuses with 400 'Expected UploadFile'.
const items = $input.all();
for (const item of items) {
  if (item.binary && item.binary.data) {
    if (!item.binary.data.fileName) {
      const mt = String(item.binary.data.mimeType || 'audio/ogg').toLowerCase();
      let ext = 'ogg';
      if (mt.includes('mpeg')) ext = 'mp3';
      else if (mt.includes('mp4') || mt.includes('m4a')) ext = 'm4a';
      else if (mt.includes('wav')) ext = 'wav';
      else if (mt.includes('webm')) ext = 'webm';
      else if (mt.includes('opus') || mt.includes('ogg')) ext = 'ogg';
      const fromInput = String(item.json?.audio_filename || '').trim();
      item.binary.data.fileName = fromInput || ('audio.' + ext);
    }
  }
}
return items;

// Re-emite el output de BIT para que el toolWorkflow devuelva
// al LLM exactamente lo que BIT computó (con quote per-item),
// no el resultado del UPDATE de Postgres.
return $('Build Inventory Tool Response').all();
